import { useEffect } from 'react';
import '@bilkobibitkov/host-kit/styles/game-tokens.css';
import { useGameStore } from './state/store';
import { DailyHero } from './features/daily/DailyHero';
import { useGameWonSubscriber, useToastStore } from './features/daily/achievements';
import { toYMD } from './lib/date';
import './features/daily/daily.css';
import './styles/themes/light.css';
import './styles/themes/dark.css';
import './styles/themes/sepia.css';
import './styles/themes/colorblind-safe.css';
import './styles/forced-colors.css';
import './styles/theme.css';
import './styles/globals.css';
import './features/anim/anim.css';
import { GameShell } from '@bilkobibitkov/host-kit';
import { bus } from './lib/bus';
import { EngineSlot } from './slots/EngineSlot';
import { BoardSlot } from './slots/BoardSlot';
import { HudSlot } from './slots/HudSlot';
import { HintsSlot } from './slots/HintsSlot';
import { ThemeSlot } from './slots/ThemeSlot';

const MINDSWIFFER_THEME = {
  heroGradient: 'linear-gradient(180deg, #f4f4f5 0%, #ffffff 100%)',
  glowColor: '#dc2626',
  accentText: '#1c1c1e',
  accentTextLight: '#52525b',
};

function AchievementSubscriber() {
  useGameWonSubscriber();
  return null;
}

function ToastContainer() {
  const toasts = useToastStore((s) => s.toasts);
  if (toasts.length === 0) return null;
  return (
    <div className="ms-toast-container" aria-live="polite">
      {toasts.map((t) => (
        <div key={t.id} className="ms-toast">{t.message}</div>
      ))}
    </div>
  );
}

function UrlRouter() {
  const newGame = useGameStore((s) => s.newGame);
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const d = params.get('d');
    if (!d) return;
    const date = new Date(d + 'T00:00:00Z');
    if (isNaN(date.getTime())) return;
    const todayStr = toYMD(new Date());
    if (d > todayStr) {
      window.history.replaceState({}, '', window.location.pathname + '?d=' + todayStr);
      newGame('daily');
      return;
    }
    newGame('daily', date);
    window.history.replaceState({}, '', window.location.pathname + '?d=' + d);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  return null;
}

function DailySection() {
  const difficulty = useGameStore((s) => s.difficulty);
  if (difficulty !== 'daily') return null;
  return <DailyHero />;
}

function announce(msg: string) {
  const el = document.getElementById('ms-announcer');
  if (el) { el.textContent = ''; setTimeout(() => { el.textContent = msg; }, 16); }
}

function formatTime(ms: number): string {
  const totalSec = Math.floor(ms / 1000);
  const minutes = Math.floor(totalSec / 60);
  const seconds = totalSec % 60;
  if (minutes === 0) return `${seconds} second${seconds !== 1 ? 's' : ''}`;
  if (seconds === 0) return `${minutes} minute${minutes !== 1 ? 's' : ''}`;
  return `${minutes} minute${minutes !== 1 ? 's' : ''} ${seconds} second${seconds !== 1 ? 's' : ''}`;
}

export default function App() {
  useEffect(() => {
    const offs = [
      bus.on('gameWon', ({ timeMs }) => announce(`Puzzle solved in ${formatTime(timeMs)}.`)),
      bus.on('gameLost', () => announce('Hit a mine. Game over.')),
      bus.on('hintRequested', ({ level }) => { if (level === 3) announce('Advanced hint applied.'); }),
    ];
    return () => offs.forEach(off => off());
  }, []);

  useEffect(() => {
    let lastNonBoardFocus: HTMLElement | null = null;

    const onFocusIn = (e: FocusEvent) => {
      const target = e.target as HTMLElement;
      if (target && !target.closest('.ms-board')) {
        lastNonBoardFocus = target;
      }
    };

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        const active = document.activeElement as HTMLElement | null;
        if (active?.closest('.ms-board') && lastNonBoardFocus) {
          e.preventDefault();
          lastNonBoardFocus.focus();
        }
      }
    };

    document.addEventListener('focusin', onFocusIn, true);
    document.addEventListener('keydown', onKeyDown);
    return () => {
      document.removeEventListener('focusin', onFocusIn, true);
      document.removeEventListener('keydown', onKeyDown);
    };
  }, []);

  return (
    <GameShell
      eyebrow="Bilko · Game"
      title="MindSwiffer"
      tagline="Minesweeper, swept clean. No 50/50s, no ads, no nonsense."
      theme={MINDSWIFFER_THEME}
    >
      <div
        role="status"
        aria-live="polite"
        aria-atomic="true"
        id="ms-announcer"
        style={{ position: 'absolute', left: -9999, width: 1, height: 1, overflow: 'hidden' }}
      />
      <UrlRouter />
      <AchievementSubscriber />
      <ThemeSlot />
      <DailySection />
      <HudSlot />
      <EngineSlot>
        <BoardSlot />
      </EngineSlot>
      <HintsSlot />
      <ToastContainer />
    </GameShell>
  );
}
