import type { MindSwifferEvents } from '../../lib/bus';

type GameDifficulty = MindSwifferEvents['newGame']['difficulty'];

const OPTIONS: Array<{ key: GameDifficulty; label: string }> = [
  { key: 'lite', label: 'Lite' },
  { key: 'beginner', label: 'Beginner' },
  { key: 'intermediate', label: 'Intermediate' },
  { key: 'expert', label: 'Expert' },
  { key: 'daily', label: 'Daily' },
];

export function DifficultyPicker({
  value,
  onChange,
}: {
  value: GameDifficulty;
  onChange: (d: GameDifficulty) => void;
}) {
  return (
    <div className="ms-difficulty" role="group" aria-label="Difficulty">
      {OPTIONS.map(o => (
        <button
          key={o.key}
          type="button"
          data-active={o.key === value}
          onClick={() => onChange(o.key)}
          aria-pressed={o.key === value}
        >
          {o.label}
        </button>
      ))}
    </div>
  );
}
