import { useEffect, useCallback } from 'react';
import { useGameActions } from '../../state/store';

interface Props {
  onClose: () => void;
}

export function NoGuessExplainerSheet({ onClose }: Props) {
  const { setNoGuess } = useGameActions();

  const handleSwitchToClassic = useCallback(() => {
    setNoGuess(false);
    onClose();
  }, [setNoGuess, onClose]);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [onClose]);

  return (
    <div
      className="ms-sheet-backdrop"
      onClick={onClose}
      role="presentation"
    >
      <div
        className="ms-sheet"
        onClick={e => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-label="No-guess mode explainer"
      >
        <p className="ms-explainer-title">No 50/50s.</p>
        <div className="ms-explainer-body">
          <p>
            MindSwiffer's no-guess generator only ships puzzles that are solvable by pure
            deduction from your first reveal. You'll never have to guess between two
            equally-likely cells.
          </p>
          <p>
            If a puzzle's deduction stalls, the game falls back to a classic random board.
            We'll mark that game with a small "Degraded" pill so you know.
          </p>
        </div>
        <div className="ms-explainer-actions">
          <button onClick={handleSwitchToClassic}>
            → Switch to classic mines (next game)
          </button>
          <button className="ms-btn-primary" onClick={onClose}>
            → Got it
          </button>
        </div>
      </div>
    </div>
  );
}
