import { useEffect, useRef, useState } from 'react';
import { useSaveState } from '@bilkobibitkov/host-kit';
import { makeBoard, type Board, type Coord, type Difficulty } from '../engine';
import { useGameStore, type GameState, type Status, INITIAL_GAME_STATE } from './store';
import { useSettingsStore, INITIAL_SETTINGS_STATE } from './settings';
import { toYMD } from '../lib/date';

const STORAGE_KEY = 'bilko_mindswiffer_save_v1';
const SETTINGS_KEY = 'bilko_mindswiffer_settings_v1';

// ── Serialization ──────────────────────────────────────────────────────────────

interface SavedGame {
  version: 1;
  savedAt: number;
  difficulty: Difficulty | 'daily';
  effectiveDifficulty: Difficulty;
  noGuess: boolean;
  currentGameDegraded?: boolean;
  status: Status;
  cursor: Coord | null;
  flagsPlaced: number;
  hintsUsed: number;
  gameStartedAt: number | null;
  gameEndedAt: number | null;
  generatedFor: Coord | null;
  dailyDate?: string | null;
  boardMeta: { rows: number; cols: number; mineCount: number; lostAt?: Coord };
  boardCells: string; // "S:m:c,..." where S=C/R/F, m=0/1, c=count
}

interface PersistedSettings {
  noGuess: boolean;
  hintCostVisible: boolean;
  haptics: boolean;
  sounds: boolean;
  soundVolume: number;
}

function serializeCells(board: Board): string {
  const parts: string[] = new Array(board.cells.length);
  for (let i = 0; i < board.cells.length; i++) {
    const cell = board.cells[i]!;
    const s = cell.state === 'covered' ? 'C' : cell.state === 'revealed' ? 'R' : 'F';
    parts[i] = `${s}:${cell.isMine ? 1 : 0}:${cell.count}`;
  }
  return parts.join(',');
}

function deserializeCells(packed: string, rows: number, cols: number): Board['cells'] {
  const parts = packed.split(',');
  const cells = new Array(parts.length);
  for (let i = 0; i < parts.length; i++) {
    const [s, m, c] = parts[i]!.split(':');
    cells[i] = Object.freeze({
      state: (s === 'R' ? 'revealed' : s === 'F' ? 'flagged' : 'covered') as Board['cells'][0]['state'],
      isMine: m === '1',
      count: parseInt(c!, 10),
    });
  }
  return Object.freeze(cells);
}

export function serializeState(state: GameState): SavedGame {
  return {
    version: 1,
    savedAt: Date.now(),
    difficulty: state.difficulty,
    effectiveDifficulty: state.effectiveDifficulty,
    noGuess: state.noGuess,
    currentGameDegraded: state.currentGameDegraded,
    status: state.status,
    cursor: state.cursor,
    flagsPlaced: state.flagsPlaced,
    hintsUsed: state.hintsUsed,
    gameStartedAt: state.gameStartedAt,
    gameEndedAt: state.gameEndedAt,
    generatedFor: state.generatedFor,
    dailyDate: state.dailyDate,
    boardMeta: {
      rows: state.board.rows,
      cols: state.board.cols,
      mineCount: state.board.mineCount,
      lostAt: state.board.lostAt,
    },
    boardCells: serializeCells(state.board),
  };
}

export function deserializeState(raw: string): (GameState & { savedAt: number }) | null {
  try {
    const saved = JSON.parse(raw) as SavedGame;
    if (saved.version !== 1) return null;

    const { rows, cols, mineCount, lostAt } = saved.boardMeta;
    const cells = deserializeCells(saved.boardCells, rows, cols);
    const board: Board = Object.freeze({
      rows, cols, mineCount, cells,
      ...(lostAt ? { lostAt } : {}),
    });

    return {
      savedAt: saved.savedAt,
      difficulty: saved.difficulty,
      effectiveDifficulty: saved.effectiveDifficulty,
      noGuess: saved.noGuess,
      currentGameDegraded: saved.currentGameDegraded ?? false,
      hintCostVisible: INITIAL_GAME_STATE.hintCostVisible,
      board,
      status: saved.status,
      cursor: saved.cursor,
      flagsPlaced: saved.flagsPlaced,
      hintsUsed: saved.hintsUsed,
      hintHighlight: [],
      gameStartedAt: saved.gameStartedAt,
      gameEndedAt: saved.gameEndedAt,
      generatedFor: saved.generatedFor,
      dailyDate: saved.dailyDate ?? null,
    };
  } catch {
    return null;
  }
}

// ── Boot hydration ────────────────────────────────────────────────────────────

export function dailyStorageKey(date: string): string {
  return `bilko_mindswiffer_daily_${date}`;
}

export function loadLocalSave(): void {
  // Prefer today's in-progress daily game over a free-play save.
  const today = toYMD(new Date());
  const dailyRaw = localStorage.getItem(dailyStorageKey(today));
  if (dailyRaw) {
    const state = deserializeState(dailyRaw);
    if (state?.status === 'playing') {
      const { savedAt: _, ...gameState } = state;
      useGameStore.setState(gameState);
      return;
    }
  }

  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return;

  const state = deserializeState(raw);
  if (!state) return;

  if (state.status === 'playing') {
    const { savedAt: _, ...gameState } = state;
    useGameStore.setState(gameState);
  } else {
    // Restore the last-played difficulty preference only.
    useGameStore.setState({ difficulty: state.difficulty, effectiveDifficulty: state.effectiveDifficulty });
  }
}

export function getLocalSaveTimestamp(): number | null {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return null;
  try {
    const saved = JSON.parse(raw) as { savedAt?: number };
    return saved.savedAt ?? null;
  } catch {
    return null;
  }
}

// ── Settings persistence ──────────────────────────────────────────────────────

export function loadSettings(): void {
  const raw = localStorage.getItem(SETTINGS_KEY);
  if (!raw) return;
  try {
    const s = JSON.parse(raw) as Partial<PersistedSettings>;
    useGameStore.setState({
      ...(s.noGuess !== undefined ? { noGuess: s.noGuess } : {}),
      ...(s.hintCostVisible !== undefined ? { hintCostVisible: s.hintCostVisible } : {}),
    });
    useSettingsStore.setState({
      ...(s.haptics !== undefined ? { haptics: s.haptics } : {}),
      ...(s.sounds !== undefined ? { sounds: s.sounds } : {}),
      ...(s.soundVolume !== undefined ? { soundVolume: s.soundVolume } : {}),
    });
  } catch {
    // ignore malformed settings
  }
}

export function initSettingsPersist(): () => void {
  const save = () => {
    const game = useGameStore.getState();
    const snd = useSettingsStore.getState();
    localStorage.setItem(SETTINGS_KEY, JSON.stringify({
      noGuess: game.noGuess,
      hintCostVisible: game.hintCostVisible,
      haptics: snd.haptics,
      sounds: snd.sounds,
      soundVolume: snd.soundVolume,
    } satisfies PersistedSettings));
  };
  const unsub1 = useGameStore.subscribe(save);
  const unsub2 = useSettingsStore.subscribe(save);
  return () => { unsub1(); unsub2(); };
}

export function resetAllData(): void {
  localStorage.removeItem(STORAGE_KEY);
  localStorage.removeItem(SETTINGS_KEY);
  useGameStore.setState({ ...INITIAL_GAME_STATE });
  useSettingsStore.setState({ ...INITIAL_SETTINGS_STATE });
}

// ── Autosave subscriber ───────────────────────────────────────────────────────

let _debounceTimer: ReturnType<typeof setTimeout> | null = null;

export function initAutosave(): () => void {
  const unsubscribe = useGameStore.subscribe((state) => {
    if (_debounceTimer) clearTimeout(_debounceTimer);
    _debounceTimer = setTimeout(() => {
      const key = (state.difficulty === 'daily' && state.dailyDate)
        ? dailyStorageKey(state.dailyDate)
        : STORAGE_KEY;

      if (state.status === 'playing') {
        localStorage.setItem(key, JSON.stringify(serializeState(state)));
      } else if (state.status === 'won' || state.status === 'lost') {
        localStorage.removeItem(key);
      }
    }, 400);
  });
  return unsubscribe;
}

// ── Cloud save comparison helper ──────────────────────────────────────────────

/** Returns true when the cloud save is strictly newer than the local save. */
export function cloudIsNewer(
  cloudUpdatedAt: number,  // Unix seconds from host-kit API
  localUpdatedAtMs: number | null,  // Date.now() ms, or null if no local save
): boolean {
  if (cloudUpdatedAt === 0) return false;
  if (localUpdatedAtMs === null) return true;
  return cloudUpdatedAt > Math.floor(localUpdatedAtMs / 1000);
}

// ── CloudSaveBridge React component ──────────────────────────────────────────

interface CloudBlob {
  snapshot: SavedGame;
  updatedAt: number;
}

const RESUME_TIMEOUT_MS = 5000;

export function CloudSaveBridge(): null {
  const { blob, version, updated_at, loading, save } =
    useSaveState<CloudBlob>('mindswiffer');

  const [showPrompt, setShowPrompt] = useState(false);
  const pendingBlobRef = useRef<CloudBlob | null>(null);
  const mounted = useRef(false);

  // On first load: compare cloud vs local, maybe show resume prompt.
  useEffect(() => {
    if (loading) return;
    if (mounted.current) return;
    mounted.current = true;

    if (!blob) return;

    const localTs = getLocalSaveTimestamp();
    if (cloudIsNewer(updated_at, localTs)) {
      pendingBlobRef.current = blob;
      setShowPrompt(true);

      // Auto-dismiss after 5s — default to local.
      const t = setTimeout(() => setShowPrompt(false), RESUME_TIMEOUT_MS);
      return () => clearTimeout(t);
    }
  }, [loading, blob, updated_at]);

  // If prompt accepted, hydrate from cloud blob.
  const acceptCloudSave = (): void => {
    const pending = pendingBlobRef.current;
    if (!pending) return;
    const state = deserializeState(JSON.stringify(pending.snapshot));
    if (state && state.status === 'playing') {
      const { savedAt: _, ...gameState } = state;
      useGameStore.setState(gameState);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(pending.snapshot));
    }
    setShowPrompt(false);
  };

  const dismissCloudSave = (): void => setShowPrompt(false);

  // Cloud save on every state change (debounced 400ms via subscribe).
  useEffect(() => {
    const unsubscribe = useGameStore.subscribe((state) => {
      if (state.status !== 'playing') return;
      if (!save) return;
      // Piggyback on the same 400ms cadence as localStorage.
      setTimeout(() => {
        void save({
          snapshot: serializeState(state),
          updatedAt: Date.now(),
        });
      }, 400);
    });
    return unsubscribe;
  }, [save]);

  // Render the resume modal into the DOM when needed.
  // We use a portal-free approach since we're returning null from this component
  // and the prompt is rendered by the parent via context/event.
  // For now: emit a custom event the app shell can catch.
  useEffect(() => {
    if (showPrompt) {
      const event = new CustomEvent('mindswiffer:resume-prompt', {
        detail: { accept: acceptCloudSave, dismiss: dismissCloudSave },
      });
      window.dispatchEvent(event);
    }
  }, [showPrompt]); // eslint-disable-line react-hooks/exhaustive-deps

  void version;
  return null;
}
