import { useEffect } from 'react';
import './hints.css';

interface ExplanationCardProps {
  text: string;
  technique: string;
  onClose: () => void;
}

function formatTechnique(t: string): string {
  return t.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

export function ExplanationCard({ text, technique, onClose }: ExplanationCardProps) {
  return (
    <>
      <div className="ms-hint-backdrop" onClick={onClose} aria-hidden />
      <div className="ms-hint-card" role="dialog" aria-label="Hint explanation">
        <div className="ms-hint-card-header">
          <span className="ms-hint-technique">{formatTechnique(technique)}</span>
          <button className="ms-hint-close" onClick={onClose} aria-label="Close hint">×</button>
        </div>
        <p className="ms-hint-card-text">{text}</p>
      </div>
    </>
  );
}

interface HintToastProps {
  message: string;
  onDismiss: () => void;
}

export function HintToast({ message, onDismiss }: HintToastProps) {
  useEffect(() => {
    const t = setTimeout(onDismiss, 2500);
    return () => clearTimeout(t);
  }, [onDismiss]);

  return <div className="ms-hint-toast">{message}</div>;
}
