import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { bus } from './lib/bus';
import { useGameStore } from './state/store';
import { loadLocalSave, loadSettings, initAutosave, initSettingsPersist } from './state/persistence';
import { startSoundHapticsSubscriber } from './features/sound/subscribe';
import { loadBuffer } from './features/sound/audio';
import { SOUNDS_BASE64 } from './features/sound/sounds';

if (import.meta.env.DEV) {
  const w = window as unknown as Record<string, unknown>;
  w['__ms_bus'] = bus;
  w['__ms_store'] = useGameStore;
  w['__gameStore'] = useGameStore;
}

const el = document.getElementById('root');
if (!el) throw new Error('Root element not found');

loadSettings();
loadLocalSave();
initAutosave();
initSettingsPersist();

startSoundHapticsSubscriber();

// Lazy: defer AudioContext creation + buffer decode until first pointer interaction.
// AudioContext must not be created on page load (autoplay policy).
addEventListener('pointerdown', function once() {
  removeEventListener('pointerdown', once);
  void Promise.all(Object.entries(SOUNDS_BASE64).map(([n, b]) => loadBuffer(n, b)));
}, { once: true });

createRoot(el).render(
  <StrictMode>
    <App />
  </StrictMode>,
);
