import { useHintStore } from '../../features/hints/store';

export function HintButton() {
  const { level, tap } = useHintStore();
  const dots = (['·', '·', '·'] as const).map((d, i) => (i < level ? '●' : d)).join(' ');
  return (
    <button className="ms-hint-btn" onClick={tap} aria-label="Hint">
      💡 <span className="ms-hint-dots" aria-hidden>{dots}</span>
    </button>
  );
}
