import { useEffect, useRef } from 'react';
import { useSaveState } from '@bilkobibitkov/host-kit';
import { useStreakStore, type StreakState } from './streakStore';

export function StreakCloudBridge(): null {
  const { blob, updated_at, loading, save } = useSaveState<StreakState>('mindswiffer-streak');
  const mounted = useRef(false);

  // On first load: if cloud has more completed days, prefer it.
  useEffect(() => {
    if (loading || !blob) return;
    if (mounted.current) return;
    mounted.current = true;

    const local = useStreakStore.getState();
    if (blob.completed.length > local.completed.length) {
      useStreakStore.getState().hydrate(blob);
    }
  }, [loading, blob, updated_at]);

  // Sync to cloud on every streak change (no debounce — writes are rare).
  useEffect(() => {
    return useStreakStore.subscribe(({ current, longest, freezes, lastWinDate, completed }) => {
      if (!save) return;
      if (completed.length === 0) return; // avoid overwriting cloud with empty cold-start state
      void save({ current, longest, freezes, lastWinDate, completed });
    });
  }, [save]);

  return null;
}
