import { useState } from 'react';
import { useLeaderboard } from '@bilkobibitkov/host-kit';

type Range = 'today' | 'week' | 'all';

const RANGE_LABELS: Record<Range, string> = { today: 'Today', week: 'This week', all: 'All time' };

function formatTime(ms: number): string {
  const m = Math.floor(ms / 60_000);
  const s = Math.floor((ms / 1000) % 60);
  return `${m}:${String(s).padStart(2, '0')}`;
}

export function Leaderboard({ difficulty }: { difficulty: string }) {
  const [range, setRange] = useState<Range>('today');
  const { scores, loading, error } = useLeaderboard('mindswiffer', { range, mode: difficulty, limit: 10 });

  return (
    <div className="ms-leaderboard">
      <div className="ms-leaderboard-header">
        <span className="ms-leaderboard-title">Top times · {difficulty.charAt(0).toUpperCase() + difficulty.slice(1)}</span>
        <div className="ms-leaderboard-tabs" role="group">
          {(['today', 'week', 'all'] as Range[]).map((r) => (
            <button
              key={r}
              type="button"
              data-active={r === range}
              onClick={() => setRange(r)}
            >
              {RANGE_LABELS[r]}
            </button>
          ))}
        </div>
      </div>

      {loading && <p className="ms-leaderboard-empty">Loading…</p>}
      {error && <p className="ms-leaderboard-empty">Could not load scores.</p>}
      {!loading && !error && scores.length === 0 && (
        <p className="ms-leaderboard-empty">No scores yet — be the first!</p>
      )}

      {!loading && scores.length > 0 && (
        <ol className="ms-leaderboard-list">
          {scores.map((row, i) => (
            <li key={i} className="ms-leaderboard-row">
              <span className="ms-leaderboard-rank">{i + 1}</span>
              <span className="ms-leaderboard-name">{row.display_name}</span>
              <span className="ms-leaderboard-score">{formatTime(row.score)}</span>
            </li>
          ))}
        </ol>
      )}
    </div>
  );
}
