import { useId } from 'react';

export function NoGuessToggle({
  value,
  onChange,
  showTooltip,
}: {
  value: boolean;
  onChange: (v: boolean) => void;
  showTooltip?: boolean;
}) {
  const id = useId();
  return (
    <label className="ms-noguess" htmlFor={id}>
      <input
        id={id}
        className="ms-noguess-input"
        type="checkbox"
        checked={value}
        onChange={e => onChange(e.target.checked)}
        aria-label={value ? 'No-guess mode on' : 'Classic mines mode'}
      />
      <span className="ms-noguess-pill" />
      <span>{value ? 'No-guess' : 'Classic mines'}</span>
      {showTooltip && (
        <span className="ms-noguess-tooltip" role="tooltip">
          Applies on next game
        </span>
      )}
    </label>
  );
}
