import './theme-picker.css';
import { THEMES, type Theme, useThemeStore } from './themes';

const THEME_LABELS: Record<Theme, string> = {
  system: 'System',
  light: 'Light',
  dark: 'Dark',
  sepia: 'Sepia',
  'colorblind-safe': 'Color-blind safe',
};

const THEME_SWATCHES: Record<Theme, { paper: string; cover: string; num: string }> = {
  system: { paper: '#ffffff', cover: '#d4d4d8', num: '#2563eb' },
  light: { paper: '#ffffff', cover: '#d4d4d8', num: '#2563eb' },
  dark: { paper: '#1c1c1e', cover: '#3f3f46', num: '#60a5fa' },
  sepia: { paper: '#f5ecd9', cover: '#d8c8a8', num: '#5c3d2e' },
  'colorblind-safe': { paper: '#ffffff', cover: '#d4d4d8', num: '#1f77b4' },
};

export function ThemePicker() {
  const { theme, setTheme } = useThemeStore();

  return (
    <div className="ms-theme-picker" role="radiogroup" aria-labelledby="ms-theme-label">
      <div id="ms-theme-label" className="ms-settings-section-label">Theme</div>
      <div className="ms-theme-options">
        {THEMES.map((t) => {
          const swatch = THEME_SWATCHES[t];
          return (
            <label key={t} className={`ms-theme-option${theme === t ? ' is-selected' : ''}`}>
              <input
                type="radio"
                name="ms-theme"
                value={t}
                checked={theme === t}
                onChange={() => setTheme(t)}
                className="ms-theme-radio"
              />
              <span
                className="ms-theme-swatch"
                style={{ background: swatch.paper, borderColor: swatch.cover }}
                aria-hidden="true"
              >
                <span
                  className="ms-theme-swatch-cell"
                  style={{ background: swatch.cover }}
                />
                <span
                  className="ms-theme-swatch-num"
                  style={{ color: swatch.num }}
                >
                  1
                </span>
              </span>
              <span className="ms-theme-name">{THEME_LABELS[t]}</span>
            </label>
          );
        })}
      </div>
    </div>
  );
}
