import { useState, useEffect, useRef, useCallback } from 'react';
import { useGameTimer, useVisibilityPause } from '@bilkobibitkov/host-kit';
import { DIFFICULTY_PRESETS, dailyDifficulty } from '../../engine';
import { bus, type MindSwifferEvents } from '../../lib/bus';
import { useGameStore } from '../../state/store';
import { NoGuessBadge, SettingsSheet } from '../../features/no-guess';
import { MineCounter } from './MineCounter';
import { Timer } from './Timer';
import { RestartButton } from './RestartButton';
import { DifficultyPicker } from './DifficultyPicker';
import { NoGuessToggle } from './NoGuessToggle';
import { ConfirmNewGameSheet } from './ConfirmNewGameSheet';
import { HintButton } from './HintButton';
import './hud.css';
import '../../features/no-guess/no-guess.css';

type GameDifficulty = MindSwifferEvents['newGame']['difficulty'];
type GameStatus = 'idle' | 'playing' | 'won' | 'lost';

function getMineCount(d: GameDifficulty): number {
  const preset = d === 'daily' ? DIFFICULTY_PRESETS[dailyDifficulty(new Date())] : DIFFICULTY_PRESETS[d];
  return preset.mines;
}

export function Hud() {
  const [difficulty, setDifficulty] = useState<GameDifficulty>('beginner');
  const [status, setStatus] = useState<GameStatus>('idle');
  const [flagsPlaced, setFlagsPlaced] = useState(0);
  const [mineCount, setMineCount] = useState(DIFFICULTY_PRESETS.beginner.mines);
  const [visibilityPaused, setVisibilityPaused] = useState(false);
  const [pendingDifficulty, setPendingDifficulty] = useState<GameDifficulty | null>(null);
  const [showNoGuessTooltip, setShowNoGuessTooltip] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  // Read noGuess from store so badge and toggle stay in sync.
  const noGuess = useGameStore(state => state.noGuess);
  const storeSetNoGuess = useGameStore.getState().setNoGuess;

  const statusRef = useRef<GameStatus>('idle');
  statusRef.current = status;
  const tooltipTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const offs = [
      bus.on('newGame', ({ difficulty: d }) => {
        setDifficulty(d);
        setStatus('idle');
        setFlagsPlaced(0);
        setMineCount(getMineCount(d));
      }),
      bus.on('cellRevealed', () => {
        setStatus(prev => (prev === 'idle' ? 'playing' : prev));
      }),
      bus.on('cellFlagged', ({ flagged }) => {
        setFlagsPlaced(prev => prev + (flagged ? 1 : -1));
      }),
      bus.on('gameWon', () => setStatus('won')),
      bus.on('gameLost', () => setStatus('lost')),
    ];
    return () => offs.forEach(off => off());
  }, []);

  const paused = status !== 'playing' || visibilityPaused;
  const { ms, reset } = useGameTimer({ paused });

  const onVisibilityPause = useCallback(() => setVisibilityPaused(true), []);
  const onVisibilityResume = useCallback(() => {
    if (statusRef.current === 'playing') setVisibilityPaused(false);
  }, []);
  useVisibilityPause(onVisibilityPause, onVisibilityResume);

  const doNewGame = useCallback(
    (d: GameDifficulty) => {
      reset();
      bus.emit('newGame', { difficulty: d });
      bus.emit('difficultyChanged', { difficulty: d });
    },
    [reset],
  );

  const requestNewGame = useCallback(
    (d: GameDifficulty) => {
      if (statusRef.current === 'playing') {
        setPendingDifficulty(d);
      } else {
        doNewGame(d);
      }
    },
    [doNewGame],
  );

  const confirmNewGame = useCallback(() => {
    setPendingDifficulty(prev => {
      if (prev) doNewGame(prev);
      return null;
    });
  }, [doNewGame]);

  const cancelNewGame = useCallback(() => setPendingDifficulty(null), []);

  const handleNoGuessChange = useCallback((v: boolean) => {
    storeSetNoGuess(v);
    if (statusRef.current === 'playing') {
      setShowNoGuessTooltip(true);
      if (tooltipTimer.current) clearTimeout(tooltipTimer.current);
      tooltipTimer.current = setTimeout(() => setShowNoGuessTooltip(false), 2000);
    }
  }, [storeSetNoGuess]);

  return (
    <div className="ms-hud">
      <MineCounter remaining={mineCount - flagsPlaced} />
      <RestartButton onClick={() => requestNewGame(difficulty)} />
      <Timer ms={ms} />
      <HintButton />
      <DifficultyPicker value={difficulty} onChange={requestNewGame} />
      <NoGuessBadge />
      <NoGuessToggle value={noGuess} onChange={handleNoGuessChange} showTooltip={showNoGuessTooltip} />
      <button
        className="ms-settings-btn"
        type="button"
        aria-label="Game settings"
        onClick={() => setShowSettings(true)}
      >
        <svg width="18" height="18" viewBox="0 0 18 18" fill="none" aria-hidden="true">
          <circle cx="9" cy="9" r="2.5" stroke="currentColor" strokeWidth="1.5"/>
          <path
            d="M9 1.5v1.75M9 14.75V16.5M1.5 9h1.75M14.75 9H16.5M3.697 3.697l1.237 1.237M13.066 13.066l1.237 1.237M14.303 3.697l-1.237 1.237M4.934 13.066l-1.237 1.237"
            stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"
          />
        </svg>
      </button>
      {pendingDifficulty !== null && (
        <ConfirmNewGameSheet onConfirm={confirmNewGame} onCancel={cancelNewGame} />
      )}
      {showSettings && <SettingsSheet onClose={() => setShowSettings(false)} />}
    </div>
  );
}
