import { create } from 'zustand';

export interface HintState {
  level: 0 | 1 | 2 | 3;
  lastTickAt: number;
  cardOpen: boolean;
  cardText: string | null;
  cardTechnique: string | null;
}

export const useHintStore = create<HintState & { tap: () => void; closeCard: () => void }>((set, get) => ({
  level: 0,
  lastTickAt: 0,
  cardOpen: false,
  cardText: null,
  cardTechnique: null,

  tap() {
    const now = Date.now();
    const stale = now - get().lastTickAt > 4000;
    const next = (stale ? 1 : Math.min(3, get().level + 1)) as 1 | 2 | 3;
    set({ level: next, lastTickAt: now });
  },

  closeCard() {
    set({ cardOpen: false });
  },
}));
