import { createBus } from '@bilkobibitkov/host-kit';

export type Coord = { row: number; col: number };

export type MindSwifferEvents = {
  cellRevealed: Coord & { auto: boolean };
  cellFlagged: Coord & { flagged: boolean };
  chordRequested: Coord;
  cursorMoved: Coord;
  hintRequested: { level: 1 | 2 | 3 };
  newGame: { difficulty: 'lite' | 'beginner' | 'intermediate' | 'expert' | 'daily' };
  gameLost: { mines: Coord[]; firstMine: Coord; timeMs: number };
  gameWon: { difficulty: string; timeMs: number; flagsUsed: number; hintsUsed: number };
  difficultyChanged: { difficulty: string };
};

export const bus = createBus<MindSwifferEvents>();
