import { useEffect, useState, type ReactNode } from 'react';
import { CloudSaveBridge } from '../state/persistence';
import { StreakCloudBridge } from '../features/daily/StreakCloudBridge';
import { Confetti } from '../features/anim/confetti';
import { WinWash } from '../features/anim/win-wash';
import { useGameState } from '../state/store';

interface Props { children?: ReactNode }

function WinEffects() {
  const status = useGameState().status;
  const [showing, setShowing] = useState(false);

  useEffect(() => {
    if (status === 'won') {
      setShowing(true);
      const t = setTimeout(() => setShowing(false), 720);
      return () => clearTimeout(t);
    }
  }, [status]);

  if (!showing) return null;
  return <><WinWash /><Confetti /></>;
}

export function EngineSlot({ children }: Props) {
  return (
    <div data-slot="engine">
      <CloudSaveBridge />
      <StreakCloudBridge />
      <WinEffects />
      {children}
    </div>
  );
}
