import { Board, Cell, Coord, neighbors, setCell, withLostAt } from './board';

export function reveal(b: Board, c: Coord): Board {
  const idx = c.row * b.cols + c.col;
  const cell = b.cells[idx] as Cell | undefined;
  if (!cell || cell.state !== 'covered') return b;
  if (cell.isMine) return withLostAt(setCell(b, c, { state: 'revealed' }), c);

  // Iterative flood-fill through zero cells.
  const next = b.cells.slice() as Cell[];
  const stack: Coord[] = [c];
  const visited = new Set<number>();

  while (stack.length > 0) {
    const cur = stack.pop()!;
    const i = cur.row * b.cols + cur.col;
    if (visited.has(i)) continue;
    visited.add(i);
    const curCell = next[i] as Cell;
    if (curCell.state !== 'covered') continue;
    next[i] = Object.freeze({ ...curCell, state: 'revealed' });
    if (curCell.count === 0) {
      for (const n of neighbors(b.rows, b.cols, cur)) {
        if (!visited.has(n.row * b.cols + n.col)) stack.push(n);
      }
    }
  }

  return Object.freeze({ ...b, cells: Object.freeze(next) });
}

/** Toggles flag on a covered cell; no-op on revealed cells. */
export function flag(b: Board, c: Coord): Board {
  const cell = b.cells[c.row * b.cols + c.col] as Cell | undefined;
  if (!cell || cell.state === 'revealed') return b;
  return setCell(b, c, { state: cell.state === 'flagged' ? 'covered' : 'flagged' });
}

/** Reveals all unflagged covered neighbors of a satisfied number cell. */
export function chord(b: Board, c: Coord): Board {
  const cell = b.cells[c.row * b.cols + c.col] as Cell | undefined;
  if (!cell || cell.state !== 'revealed' || cell.count <= 0) return b;
  const ns = neighbors(b.rows, b.cols, c);
  const flaggedCount = ns.filter(n => (b.cells[n.row * b.cols + n.col] as Cell).state === 'flagged').length;
  if (flaggedCount !== cell.count) return b;
  let next = b;
  for (const n of ns) {
    if ((next.cells[n.row * next.cols + n.col] as Cell).state === 'covered') {
      next = reveal(next, n);
    }
  }
  return next;
}

export function isWon(b: Board): boolean {
  for (const cell of b.cells) {
    if (!(cell as Cell).isMine && (cell as Cell).state !== 'revealed') return false;
  }
  return true;
}

export function isLost(b: Board): boolean {
  return b.lostAt !== undefined;
}
