export type CellState = 'covered' | 'revealed' | 'flagged';

export interface Cell {
  readonly state: CellState;
  readonly isMine: boolean;
  /** Mines in 8 neighbors. -1 if this cell is a mine. */
  readonly count: number;
}

export interface Coord { row: number; col: number; }

export interface Board {
  readonly rows: number;
  readonly cols: number;
  readonly mineCount: number;
  /** Row-major. Frozen. */
  readonly cells: ReadonlyArray<Cell>;
  readonly lostAt?: Coord;
}

export type Difficulty = 'lite' | 'beginner' | 'intermediate' | 'expert';

export const DIFFICULTY_PRESETS: Record<Difficulty, { rows: number; cols: number; mines: number }> = {
  lite:         { rows: 5,  cols: 5,  mines:  3 },
  beginner:     { rows: 9,  cols: 9,  mines: 10 },
  intermediate: { rows: 16, cols: 16, mines: 40 },
  expert:       { rows: 16, cols: 30, mines: 99 },
} as const;

/** Returns up to 8 valid neighbor coords. O(8) per call. */
export function neighbors(rows: number, cols: number, c: Coord): Coord[] {
  const result: Coord[] = [];
  for (let dr = -1; dr <= 1; dr++) {
    for (let dc = -1; dc <= 1; dc++) {
      if (dr === 0 && dc === 0) continue;
      const r = c.row + dr, cl = c.col + dc;
      if (r >= 0 && r < rows && cl >= 0 && cl < cols) result.push({ row: r, col: cl });
    }
  }
  return result;
}

/** Builds a fresh all-covered board from a set of mine flat-indices. */
export function makeBoard(rows: number, cols: number, mineSet: Set<number>): Board {
  const cells: Cell[] = new Array(rows * cols);
  for (let i = 0; i < rows * cols; i++) {
    const isMine = mineSet.has(i);
    const row = Math.floor(i / cols);
    const col = i % cols;
    let count = -1;
    if (!isMine) {
      count = 0;
      for (let dr = -1; dr <= 1; dr++) {
        for (let dc = -1; dc <= 1; dc++) {
          if (dr === 0 && dc === 0) continue;
          const nr = row + dr, nc = col + dc;
          if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && mineSet.has(nr * cols + nc)) count++;
        }
      }
    }
    cells[i] = Object.freeze({ state: 'covered', isMine, count });
  }
  return Object.freeze({ rows, cols, mineCount: mineSet.size, cells: Object.freeze(cells) });
}

/** Returns a new board with one cell patched. O(n) due to slice. */
export function setCell(b: Board, c: Coord, patch: Partial<Cell>): Board {
  const idx = c.row * b.cols + c.col;
  const next = b.cells.slice() as Cell[];
  next[idx] = Object.freeze({ ...(next[idx] as Cell), ...patch });
  return Object.freeze({ ...b, cells: Object.freeze(next) });
}

export function withLostAt(b: Board, c: Coord): Board {
  return Object.freeze({ ...b, lostAt: c });
}
