import { Difficulty } from './board';

// Mon=lite, Tue=beg, Wed=beg, Thu=int, Fri=int, Sat=exp, Sun=exp
const DOW_MAP: Difficulty[] = ['expert', 'lite', 'beginner', 'beginner', 'intermediate', 'intermediate', 'expert'];

export function dailyDifficulty(date: Date): Difficulty {
  return DOW_MAP[date.getUTCDay()] ?? 'beginner';
}

export function dailySeed(date: Date): number {
  const y = date.getUTCFullYear(), m = date.getUTCMonth() + 1, d = date.getUTCDate();
  return ((y * 100 + m) * 100 + d) >>> 0;
}
