import { useEffect } from 'react';
import { create } from 'zustand';
import { useUnlocks, useLeaderboard } from '@bilkobibitkov/host-kit';
import { bus } from '../../lib/bus';
import { useGameStore } from '../../state/store';
import { useStreakStore } from './streakStore';
import { toYMD } from '../../lib/date';

// ── Toast store ───────────────────────────────────────────────────────────────

interface Toast { id: number; message: string }

let _toastId = 0;

export const useToastStore = create<{ toasts: Toast[]; show(msg: string): void }>((set) => ({
  toasts: [],
  show(message) {
    const id = ++_toastId;
    set((s) => ({ toasts: [...s.toasts, { id, message }] }));
    setTimeout(() => set((s) => ({ toasts: s.toasts.filter((t) => t.id !== id) })), 4000);
  },
}));

// ── Achievement + leaderboard subscriber ──────────────────────────────────────

export function useGameWonSubscriber() {
  const { unlocks, unlock } = useUnlocks('mindswiffer');
  const { submit } = useLeaderboard('mindswiffer', { range: 'all', limit: 10 });
  const show = useToastStore((s) => s.show);

  const hasUnlock = (key: string) => unlocks.some((u) => u.key === key);

  const tryUnlock = async (key: string, name: string) => {
    if (hasUnlock(key)) return;
    const ok = await unlock(key);
    if (ok) show(`🏆 Achievement unlocked: ${name}`);
  };

  useEffect(() => {
    return bus.on('gameWon', ({ difficulty, timeMs, flagsUsed, hintsUsed }) => {
      const storeDifficulty = useGameStore.getState().difficulty;
      const dailyDate = useGameStore.getState().dailyDate;

      // Leaderboard: submit for daily games only (today's date, not replays).
      if (storeDifficulty === 'daily' && dailyDate === toYMD(new Date())) {
        void submit(timeMs, difficulty);

        // Streak: record win.
        useStreakStore.getState().recordWin(dailyDate);

        // streak_7 achievement fires from streak state.
        const streak = useStreakStore.getState().current;
        if (streak >= 7) void tryUnlock('streak_7', 'Week-long sweep');
      }

      // Achievements (all game modes).
      void tryUnlock('first_sweep', 'First sweep');
      if (difficulty === 'beginner' && timeMs < 60_000) void tryUnlock('beginner_sub_60', 'Sub-60 Beginner');
      if (difficulty === 'intermediate' && timeMs < 180_000) void tryUnlock('intermediate_sub_180', 'Sub-3 Intermediate');
      if (difficulty === 'expert') void tryUnlock('expert_win', 'Expert sweeper');
      if (flagsUsed === 0) void tryUnlock('no_flag_win', 'Flagless');
      if (difficulty === 'intermediate' && hintsUsed === 0) void tryUnlock('no_hint_intermediate', 'Pure deduction');
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [unlocks, unlock, submit, show]);
}
