import { useEffect, useCallback, useState, useId } from 'react';
import { useGameStore, useGameActions } from '../../state/store';
import { resetAllData } from '../../state/persistence';
import { useSettingsStore } from '../../state/settings';
import { ThemePicker } from '../themes/ThemePicker';

interface Props {
  onClose: () => void;
}

export function SettingsSheet({ onClose }: Props) {
  const noGuess = useGameStore(state => state.noGuess);
  const hintCostVisible = useGameStore(state => state.hintCostVisible);
  const { setNoGuess, setHintCostVisible } = useGameActions();
  const { haptics, sounds, soundVolume, setHaptics, setSounds, setSoundVolume } = useSettingsStore();
  const [confirmReset, setConfirmReset] = useState(false);

  const noGuessId = useId();
  const hintCostId = useId();
  const hapticsId = useId();
  const soundsId = useId();
  const volumeId = useId();

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [onClose]);

  const handleReset = useCallback(() => {
    resetAllData();
    onClose();
  }, [onClose]);

  return (
    <div
      className="ms-sheet-backdrop"
      onClick={onClose}
      role="presentation"
    >
      <div
        className="ms-sheet"
        onClick={e => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-label="Game settings"
      >
        <p className="ms-settings-title">Game settings</p>

        <div className="ms-settings-theme-section">
          <ThemePicker />
        </div>

        <div className="ms-settings-list">
          <div className="ms-settings-item">
            <label className="ms-settings-label" htmlFor={noGuessId}>
              No-guess mode
              <span>Applies to next game</span>
            </label>
            <label className="ms-settings-toggle-wrap">
              <input
                id={noGuessId}
                className="ms-settings-toggle-input"
                type="checkbox"
                checked={noGuess}
                onChange={e => setNoGuess(e.target.checked)}
                aria-label="No-guess mode"
              />
              <span className="ms-settings-toggle-pill" />
            </label>
          </div>

          <div className="ms-settings-item">
            <label className="ms-settings-label" htmlFor={hintCostId}>
              Hint cost visible
              <span>Coming in a future update</span>
            </label>
            <label className="ms-settings-toggle-wrap">
              <input
                id={hintCostId}
                className="ms-settings-toggle-input"
                type="checkbox"
                checked={hintCostVisible}
                onChange={e => setHintCostVisible(e.target.checked)}
                aria-label="Hint cost visible"
              />
              <span className="ms-settings-toggle-pill" />
            </label>
          </div>

          <div className="ms-settings-item">
            <label className="ms-settings-label" htmlFor={hapticsId}>
              Haptics
              <span>Vibration on mobile (iOS: Chrome only)</span>
            </label>
            <label className="ms-settings-toggle-wrap">
              <input
                id={hapticsId}
                className="ms-settings-toggle-input"
                type="checkbox"
                checked={haptics}
                onChange={e => setHaptics(e.target.checked)}
                aria-label="Haptics"
              />
              <span className="ms-settings-toggle-pill" />
            </label>
          </div>

          <div className="ms-settings-item">
            <label className="ms-settings-label" htmlFor={soundsId}>
              Sounds
            </label>
            <label className="ms-settings-toggle-wrap">
              <input
                id={soundsId}
                className="ms-settings-toggle-input"
                type="checkbox"
                checked={sounds}
                onChange={e => setSounds(e.target.checked)}
                aria-label="Sounds"
              />
              <span className="ms-settings-toggle-pill" />
            </label>
          </div>

          {sounds && (
            <div className="ms-settings-item">
              <label className="ms-settings-label" htmlFor={volumeId}>
                Volume
              </label>
              <input
                id={volumeId}
                className="ms-settings-slider"
                type="range"
                min={0}
                max={100}
                value={soundVolume}
                onChange={e => setSoundVolume(Number(e.target.value))}
                aria-label="Sound volume"
              />
            </div>
          )}
        </div>

        <button
          className="ms-settings-reset"
          onClick={() => setConfirmReset(true)}
          type="button"
        >
          Reset all data
        </button>

        {confirmReset && (
          <div className="ms-settings-reset-confirm">
            <p>Clear all saved games and settings? This cannot be undone.</p>
            <div className="ms-settings-reset-confirm-actions">
              <button type="button" onClick={() => setConfirmReset(false)}>Cancel</button>
              <button type="button" className="ms-btn-danger" onClick={handleReset}>Reset</button>
            </div>
          </div>
        )}

        <button className="ms-settings-close" onClick={onClose} type="button">
          Done
        </button>
      </div>
    </div>
  );
}
