import { useEffect, useRef, useState } from 'react';
import { Flag } from './Flag';
import { Mine } from './Mine';
import { bus } from '../../lib/bus';
import { NumberWithGlyph } from '../../features/themes/glyph-overlay';
import type { Cell as EngineCell } from '../../engine';

interface CellProps {
  row: number;
  col: number;
  cell: EngineCell;
  cursor: boolean;
  hint: boolean;
  lossCell: boolean;
  isColorblindSafe: boolean;
  isLost: boolean;
  cascadeStep?: number;
}

function cellAriaLabel(row: number, col: number, cell: EngineCell): string {
  const pos = `Row ${row + 1}, column ${col + 1}`;
  if (cell.state === 'flagged') return `${pos}, flagged.`;
  if (cell.state === 'covered') return `${pos}, covered.`;
  if (cell.isMine) return `${pos}, mine.`;
  if (cell.count === 0) return `${pos}, empty.`;
  return `${pos}, ${cell.count} ${cell.count === 1 ? 'mine' : 'mines'} adjacent.`;
}

export function Cell({ row, col, cell, cursor, hint, lossCell, isColorblindSafe, isLost, cascadeStep }: CellProps) {
  const longPressTimer = useRef<number | null>(null);
  const startPos = useRef<{ x: number; y: number } | null>(null);
  const isLeftPointer = useRef(false);
  const prevStateRef = useRef(cell.state);
  const reducedRef = useRef(
    typeof window !== 'undefined' && matchMedia('(prefers-reduced-motion: reduce)').matches,
  );
  const [flagPlanting, setFlagPlanting] = useState(false);

  useEffect(() => {
    if (reducedRef.current) return;
    if (cell.state === 'flagged' && prevStateRef.current !== 'flagged') {
      setFlagPlanting(true);
      const t = setTimeout(() => setFlagPlanting(false), 220);
      return () => clearTimeout(t);
    }
    prevStateRef.current = cell.state;
  }, [cell.state]);

  const cancelLongPress = () => {
    if (longPressTimer.current !== null) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  const onPointerDown = (e: React.PointerEvent) => {
    isLeftPointer.current = e.button === 0;
    if (!isLeftPointer.current) return;
    startPos.current = { x: e.clientX, y: e.clientY };
    longPressTimer.current = window.setTimeout(() => {
      bus.emit('cellFlagged', { row, col, flagged: cell.state !== 'flagged' });
      longPressTimer.current = null;
    }, 350);
  };

  const onPointerMove = (e: React.PointerEvent) => {
    if (!startPos.current) return;
    if (Math.hypot(e.clientX - startPos.current.x, e.clientY - startPos.current.y) > 8) {
      cancelLongPress();
    }
  };

  const onPointerUp = () => {
    if (!isLeftPointer.current) return;
    if (longPressTimer.current !== null) {
      cancelLongPress();
      if (cell.state === 'covered') {
        bus.emit('cellRevealed', { row, col, auto: false });
      } else if (cell.state === 'revealed' && cell.count > 0) {
        bus.emit('chordRequested', { row, col });
      }
    }
  };

  const onContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    bus.emit('cellFlagged', { row, col, flagged: cell.state !== 'flagged' });
  };

  const onAuxClick = (e: React.MouseEvent) => {
    if (e.button === 1 && cell.state === 'revealed') {
      e.preventDefault();
      bus.emit('chordRequested', { row, col });
    }
  };

  // Mines revealed on loss: hit cell + all other mines shown with delay
  const dataMine =
    cell.isMine && cell.state === 'revealed'
      ? lossCell
        ? 'hit'
        : 'shown'
      : cell.isMine && isLost && !lossCell
        ? 'shown'
        : undefined;

  const showMineIcon =
    (cell.state === 'revealed' && cell.isMine) ||
    (isLost && cell.isMine && !lossCell);

  const stateClass = `ms-cell-${cell.state}`;
  const extraClasses = [
    cursor ? 'is-cursor' : '',
    hint ? 'is-hint' : '',
    lossCell ? 'is-loss' : '',
    flagPlanting && !reducedRef.current ? 'flag-plant' : '',
    dataMine === 'shown' && !reducedRef.current ? 'mines-fade-in' : '',
  ].filter(Boolean).join(' ');

  return (
    <button
      className={`ms-cell ${stateClass}${extraClasses ? ' ' + extraClasses : ''}`}
      aria-label={cellAriaLabel(row, col, cell)}
      data-state={cell.state}
      data-mine={dataMine}
      data-row={row}
      data-col={col}
      data-cursor={cursor ? 'true' : undefined}
      data-cascade-step={cascadeStep !== undefined ? cascadeStep : undefined}
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={onPointerUp}
      onPointerCancel={cancelLongPress}
      onContextMenu={onContextMenu}
      onAuxClick={onAuxClick}
      tabIndex={cursor ? 0 : -1}
    >
      {cell.state === 'flagged' && <Flag />}
      {showMineIcon && <Mine />}
      {cell.state === 'revealed' && !cell.isMine && cell.count > 0 && (
        isColorblindSafe
          ? <NumberWithGlyph count={cell.count} />
          : <span style={{ color: `var(--num-${cell.count})` }}>{cell.count}</span>
      )}
    </button>
  );
}
