export const GLYPHS = ['', '●', '▲', '■', '♦', '+', '×', '◇', '★'] as const;

export function NumberWithGlyph({ count }: { count: number }) {
  return (
    <span style={{ display: 'inline-flex', flexDirection: 'column', alignItems: 'center', lineHeight: 1, gap: 1 }}>
      <span style={{ color: `var(--num-${count})` }}>{count}</span>
      <span aria-hidden="true" style={{ fontSize: '40%', color: `var(--num-${count})` }}>
        {GLYPHS[count]}
      </span>
    </span>
  );
}
