export function Mine() {
  return (
    <svg viewBox="0 0 16 16" width="50%" height="50%" aria-hidden>
      {[0, 60, 120, 180, 240, 300].map(deg => (
        <line
          key={deg}
          x1="8" y1="8"
          x2={8 + 6.5 * Math.cos((deg * Math.PI) / 180)}
          y2={8 + 6.5 * Math.sin((deg * Math.PI) / 180)}
          stroke="var(--mine)"
          strokeWidth="1"
        />
      ))}
      <circle cx="8" cy="8" r="4.5" fill="var(--mine)" />
      <circle cx="6.5" cy="6.5" r="1" fill="var(--paper)" />
    </svg>
  );
}
