import { useState } from 'react';
import { useGameStore } from '../../state/store';
import { useStreakStore } from './streakStore';
import { CalendarSheet } from './CalendarSheet';
import { ShareTile } from './ShareTile';
import { Leaderboard } from './Leaderboard';
import { toYMD } from '../../lib/date';

const DIFF_LABEL: Record<string, string> = {
  lite: 'Lite',
  beginner: 'Beginner',
  intermediate: 'Intermediate',
  expert: 'Expert',
};

export function DailyHero() {
  const [showCalendar, setShowCalendar] = useState(false);
  const [showLeaderboard, setShowLeaderboard] = useState(false);

  const status = useGameStore((s) => s.status);
  const effectiveDifficulty = useGameStore((s) => s.effectiveDifficulty);
  const dailyDate = useGameStore((s) => s.dailyDate);
  const flagsUsed = useGameStore((s) => s.flagsPlaced);
  const hintsUsed = useGameStore((s) => s.hintsUsed);
  const gameStartedAt = useGameStore((s) => s.gameStartedAt);
  const gameEndedAt = useGameStore((s) => s.gameEndedAt);

  const streak = useStreakStore((s) => s.current);
  const freezes = useStreakStore((s) => s.freezes);

  const todayStr = toYMD(new Date());
  const isToday = dailyDate === todayStr;
  const isWon = status === 'won';

  const dateObj = dailyDate ? new Date(dailyDate + 'T00:00:00Z') : new Date();
  const dateLabel = dateObj.toLocaleDateString('en-US', {
    weekday: 'short', month: 'short', day: 'numeric', timeZone: 'UTC',
  });

  const timeMs = (gameStartedAt && gameEndedAt) ? gameEndedAt - gameStartedAt : 0;

  return (
    <>
      <div className="ms-daily-hero">
        <div className="ms-daily-hero-top">
          <div className="ms-daily-hero-info">
            <span className="ms-daily-date">{dateLabel}</span>
            <span className="ms-daily-diff">{DIFF_LABEL[effectiveDifficulty] ?? effectiveDifficulty}</span>
          </div>
          <div className="ms-daily-streak">
            {streak > 0 && <span className="ms-streak-badge">🔥 {streak}</span>}
            {freezes > 0 && <span className="ms-freeze-badge">❄️ {freezes}</span>}
          </div>
          <button
            type="button"
            className="ms-calendar-btn"
            onClick={() => setShowCalendar(true)}
            aria-label="Open puzzle calendar"
          >
            📅
          </button>
        </div>

        {isWon && isToday && (
          <div className="ms-daily-win-actions">
            <ShareTile
              date={dateObj}
              difficulty={effectiveDifficulty}
              timeMs={timeMs}
              flagsUsed={flagsUsed}
              hintsUsed={hintsUsed}
              streak={streak}
            />
            <button
              type="button"
              className="ms-leaderboard-toggle"
              onClick={() => setShowLeaderboard((v) => !v)}
            >
              {showLeaderboard ? 'Hide leaderboard' : '🏅 Leaderboard'}
            </button>
          </div>
        )}

        {isWon && showLeaderboard && (
          <Leaderboard difficulty={effectiveDifficulty} />
        )}
      </div>

      {showCalendar && <CalendarSheet onClose={() => setShowCalendar(false)} />}
    </>
  );
}
