import { create } from 'zustand';
import { toYMD, daysDiff } from '../../lib/date';

export const STREAK_KEY = 'bilko_mindswiffer_streak_v1';
const MAX_FREEZES = 3;

export interface StreakState {
  current: number;
  longest: number;
  freezes: number;
  lastWinDate: string | null; // YYYY-MM-DD
  completed: string[];         // YYYY-MM-DD[], sorted ascending
}

const DEFAULT_STREAK: StreakState = {
  current: 0,
  longest: 0,
  freezes: 0,
  lastWinDate: null,
  completed: [],
};

function loadLocal(): StreakState {
  try {
    const raw = localStorage.getItem(STREAK_KEY);
    if (!raw) return DEFAULT_STREAK;
    return { ...DEFAULT_STREAK, ...(JSON.parse(raw) as Partial<StreakState>) };
  } catch {
    return DEFAULT_STREAK;
  }
}

/**
 * Apply missed-day logic: consume freezes for each missed day; reset streak
 * if any missed day couldn't be covered.
 */
export function computeCurrentStreak(stored: StreakState, today: string): StreakState {
  if (!stored.lastWinDate) return stored;

  const gap = daysDiff(stored.lastWinDate, today);
  if (gap <= 1) return stored; // same day or consecutive — nothing to fix

  const missedDays = gap - 1;
  if (missedDays <= stored.freezes) {
    return { ...stored, freezes: stored.freezes - missedDays };
  }
  return { ...stored, current: 0, freezes: 0 };
}

export interface StreakActions {
  /** Record a daily win for `date` (YYYY-MM-DD). No-op for replays already in completed[]. */
  recordWin(date: string): void;
  /** Overwrite state wholesale (used by cloud sync bridge). */
  hydrate(state: StreakState): void;
}

export const useStreakStore = create<StreakState & StreakActions>(() => {
  const loaded = loadLocal();
  const today = toYMD(new Date());
  return { ...computeCurrentStreak(loaded, today), recordWin: _recordWin, hydrate: _hydrate };
});

function _recordWin(date: string): void {
  useStreakStore.setState((s) => {
    if (s.completed.includes(date)) return s; // already recorded

    const lastWin = s.lastWinDate;
    const gap = lastWin !== null ? daysDiff(lastWin, date) : null;

    let newCurrent: number;
    if (gap === null) {
      newCurrent = 1; // first win ever
    } else if (gap === 1) {
      newCurrent = s.current + 1; // consecutive day
    } else {
      // gap > 1: computeCurrentStreak already consumed freezes and may have reset.
      // s.current === 0 means reset → start at 1; otherwise freeze bridged → increment.
      newCurrent = s.current === 0 ? 1 : s.current + 1;
    }

    const newCompleted = [...s.completed, date];
    const newFreezesEarned = Math.floor(newCompleted.length / 7) - Math.floor(s.completed.length / 7);
    const newFreezesTotal = Math.min(s.freezes + newFreezesEarned, MAX_FREEZES);

    const next: StreakState = {
      current: newCurrent,
      longest: Math.max(s.longest, newCurrent),
      freezes: newFreezesTotal,
      lastWinDate: date,
      completed: newCompleted,
    };

    localStorage.setItem(STREAK_KEY, JSON.stringify(next));
    return next;
  });
}

function _hydrate(state: StreakState): void {
  const today = toYMD(new Date());
  const hydrated = computeCurrentStreak(state, today);
  localStorage.setItem(STREAK_KEY, JSON.stringify(hydrated));
  useStreakStore.setState({ ...hydrated });
}
