import { create } from 'zustand';
import {
  generate, reveal, flag, chord, isWon, isLost, makeBoard,
  type Board, type Difficulty, type Coord,
  dailyDifficulty, dailySeed, deterministicRng, DIFFICULTY_PRESETS,
} from '../engine';
import { bus } from '../lib/bus';
import { track } from '../lib/analytics';
import { toYMD } from '../lib/date';

export type Status = 'idle' | 'playing' | 'won' | 'lost';

export interface GameState {
  difficulty: Difficulty | 'daily';
  effectiveDifficulty: Difficulty;
  noGuess: boolean;
  currentGameDegraded: boolean;
  hintCostVisible: boolean;
  board: Board;
  status: Status;
  cursor: Coord | null;
  flagsPlaced: number;
  hintsUsed: number;
  hintHighlight: Coord[];
  gameStartedAt: number | null;
  gameEndedAt: number | null;
  generatedFor: Coord | null;
  /** YYYY-MM-DD of the daily being played; null for free-play. */
  dailyDate: string | null;
}

export interface GameActions {
  newGame: (d: Difficulty | 'daily', forDate?: Date) => void;
  doReveal: (c: Coord) => void;
  doFlag: (c: Coord) => void;
  doChord: (c: Coord) => void;
  setCursor: (c: Coord | null) => void;
  setNoGuess: (v: boolean) => void;
  setHintCostVisible: (v: boolean) => void;
  applyHintAction: (a: { type: 'reveal' | 'flag'; cells: Coord[] }) => void;
}

function blankBoard(diff: Difficulty): Board {
  const { rows, cols, mines } = DIFFICULTY_PRESETS[diff];
  const base = makeBoard(rows, cols, new Set());
  // Show correct mine count in HUD even before mines are placed.
  return Object.freeze({ ...base, mineCount: mines });
}

export const INITIAL_GAME_STATE: GameState = {
  difficulty: 'beginner',
  effectiveDifficulty: 'beginner',
  noGuess: true,
  currentGameDegraded: false,
  hintCostVisible: true,
  board: blankBoard('beginner'),
  status: 'idle',
  cursor: { row: 0, col: 0 },
  flagsPlaced: 0,
  hintsUsed: 0,
  hintHighlight: [],
  gameStartedAt: null,
  gameEndedAt: null,
  generatedFor: null,
  dailyDate: null,
};

// Re-entrancy guard: newGame() emits 'newGame' bus event; the bus.on('newGame')
// below must not call newGame() again when the store itself is the emitter.
let _inStoreNewGame = false;

export const useGameStore = create<GameState & GameActions>((set, get) => ({
  ...INITIAL_GAME_STATE,

  newGame(d, forDate?: Date) {
    _inStoreNewGame = true;
    const date = d === 'daily' ? (forDate ?? new Date()) : new Date();
    const eff = d === 'daily' ? dailyDifficulty(date) : d;
    const dailyDate = d === 'daily' ? toYMD(date) : null;
    set({
      difficulty: d,
      effectiveDifficulty: eff,
      board: blankBoard(eff),
      status: 'idle',
      flagsPlaced: 0,
      hintsUsed: 0,
      hintHighlight: [],
      gameStartedAt: null,
      gameEndedAt: null,
      generatedFor: null,
      currentGameDegraded: false,
      cursor: { row: 0, col: 0 },
      dailyDate,
    });
    bus.emit('newGame', { difficulty: d === 'daily' ? 'daily' : d });
    bus.emit('difficultyChanged', { difficulty: d === 'daily' ? 'daily' : d });
    _inStoreNewGame = false;
  },

  doReveal(c) {
    const s = get();
    if (s.status === 'won' || s.status === 'lost') return;

    let board = s.board;
    let generatedFor = s.generatedFor;
    let status = s.status;
    let gameStartedAt = s.gameStartedAt;
    let currentGameDegraded = s.currentGameDegraded;

    // Lazy generation on first reveal — guarantees first click is zero.
    if (!generatedFor) {
      const rng = s.difficulty === 'daily'
        ? deterministicRng(dailySeed(s.dailyDate ? new Date(s.dailyDate + 'T00:00:00Z') : new Date()))
        : Math.random;
      const { board: gen, degraded } = generate({
        difficulty: s.effectiveDifficulty,
        firstReveal: c,
        mode: s.noGuess ? 'no-guess' : 'classic',
        rng,
      });
      board = gen;
      generatedFor = c;
      status = 'playing';
      gameStartedAt = Date.now();
      currentGameDegraded = degraded;
      if (degraded) {
        void track('mindswiffer.degraded', { difficulty: s.effectiveDifficulty });
      }
    }

    board = reveal(board, c);

    if (isLost(board)) {
      const mines: Coord[] = [];
      for (let i = 0; i < board.cells.length; i++) {
        if (board.cells[i]!.isMine) {
          mines.push({ row: Math.floor(i / board.cols), col: i % board.cols });
        }
      }
      set({ board, status: 'lost', generatedFor, gameStartedAt, gameEndedAt: Date.now(), currentGameDegraded });
      bus.emit('gameLost', {
        mines,
        firstMine: c,
        timeMs: Date.now() - (gameStartedAt ?? Date.now()),
      });
      return;
    }

    if (isWon(board)) {
      set({ board, status: 'won', generatedFor, gameStartedAt, gameEndedAt: Date.now(), currentGameDegraded });
      bus.emit('gameWon', {
        difficulty: s.effectiveDifficulty,
        timeMs: Date.now() - gameStartedAt!,
        flagsUsed: s.flagsPlaced,
        hintsUsed: s.hintsUsed,
      });
      return;
    }

    set({ board, status, generatedFor, gameStartedAt, currentGameDegraded });
  },

  doFlag(c) {
    const s = get();
    if (!s.generatedFor) return; // no flagging before first reveal
    if (s.status === 'won' || s.status === 'lost') return;

    const idx = c.row * s.board.cols + c.col;
    const before = s.board.cells[idx]!.state;
    if (before === 'revealed') return;

    const board = flag(s.board, c);
    const after = board.cells[idx]!.state;
    set({
      board,
      flagsPlaced: s.flagsPlaced + (after === 'flagged' ? 1 : 0) - (before === 'flagged' ? 1 : 0),
    });
  },

  doChord(c) {
    const s = get();
    if (s.status === 'won' || s.status === 'lost') return;

    const board = chord(s.board, c);
    if (board === s.board) return; // no-op

    if (isLost(board)) {
      set({ board, status: 'lost', gameEndedAt: Date.now() });
      bus.emit('gameLost', {
        mines: [],
        firstMine: c,
        timeMs: Date.now() - (s.gameStartedAt ?? Date.now()),
      });
      return;
    }

    if (isWon(board)) {
      set({ board, status: 'won', gameEndedAt: Date.now() });
      bus.emit('gameWon', {
        difficulty: s.effectiveDifficulty,
        timeMs: Date.now() - s.gameStartedAt!,
        flagsUsed: s.flagsPlaced,
        hintsUsed: s.hintsUsed,
      });
      return;
    }

    set({ board });
  },

  setCursor(c) { set({ cursor: c }); },

  setNoGuess(v) { set({ noGuess: v }); },

  setHintCostVisible(v) { set({ hintCostVisible: v }); },

  applyHintAction({ type, cells }) {
    set(s => ({ hintsUsed: s.hintsUsed + 1, hintHighlight: cells }));
    setTimeout(() => set({ hintHighlight: [] }), 800);
    if (type === 'flag') cells.forEach(c => get().doFlag(c));
    else cells.forEach(c => get().doReveal(c));
  },
}));

// Bus → store wiring
bus.on('cellRevealed', ({ row, col }) => useGameStore.getState().doReveal({ row, col }));
bus.on('cellFlagged', ({ row, col }) => useGameStore.getState().doFlag({ row, col }));
bus.on('chordRequested', c => useGameStore.getState().doChord(c));
bus.on('cursorMoved', c => useGameStore.getState().setCursor(c));
// HUD emits 'newGame' when user picks a difficulty; sync to store so board resets.
bus.on('newGame', ({ difficulty }) => {
  if (_inStoreNewGame) return;
  useGameStore.getState().newGame(difficulty);
});

export const useGameState = () => useGameStore();

export const useGameActions = (): GameActions => {
  const { newGame, doReveal, doFlag, doChord, setCursor, setNoGuess, setHintCostVisible, applyHintAction } =
    useGameStore.getState();
  return { newGame, doReveal, doFlag, doChord, setCursor, setNoGuess, setHintCostVisible, applyHintAction };
};
