export function MineCounter({ remaining }: { remaining: number }) {
  const negative = remaining < 0;
  const display = negative
    ? `-${String(-remaining).padStart(2, '0')}`
    : String(remaining).padStart(3, '0');
  return (
    <div className="ms-counter" data-negative={negative} aria-label={`${remaining} mines remaining`}>
      {display}
    </div>
  );
}
