import { Board, Cell, Coord, Difficulty, DIFFICULTY_PRESETS, makeBoard, neighbors } from './board';
import { deterministicRng } from './rng';
import { deductiveSolve } from './solve';

export type Mode = 'no-guess' | 'classic';

export interface GenerateOpts {
  difficulty: Difficulty;
  firstReveal: Coord;
  mode: Mode;
  rng?: () => number;
  timeoutMs?: number;
}

const DEFAULT_TIMEOUTS: Record<Difficulty, number> = {
  lite: 500, beginner: 1500, intermediate: 4000, expert: 8000,
};

function generateClassic(
  rows: number, cols: number, mineCount: number, firstReveal: Coord, rng: () => number,
): Board {
  const total = rows * cols;
  // Exclude firstReveal and its 8 neighbors from mine candidates — guarantees count=0 there.
  const forbidden = new Set(
    [firstReveal, ...neighbors(rows, cols, firstReveal)].map(c => c.row * cols + c.col),
  );
  const candidates = Array.from({ length: total }, (_, i) => i).filter(i => !forbidden.has(i));

  // Fisher-Yates partial shuffle — take first mineCount.
  for (let i = candidates.length - 1; i > candidates.length - 1 - mineCount && i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    const tmp = candidates[i]!;
    candidates[i] = candidates[j]!;
    candidates[j] = tmp;
  }
  const mineSet = new Set(candidates.slice(candidates.length - mineCount));
  return makeBoard(rows, cols, mineSet);
}

/**
 * Swaps one mine with a non-mine outside the firstReveal forbidden zone.
 * Prefers mines on the ambiguous frontier to target stuck deduction positions.
 */
function mutateOneMine(b: Board, firstReveal: Coord, rng: () => number): Board {
  const forbidden = new Set(
    [firstReveal, ...neighbors(b.rows, b.cols, firstReveal)].map(c => c.row * b.cols + c.col),
  );

  // Collect mine candidates to remove: prefer frontier mines (covered mines adjacent to a revealed cell).
  const frontierMines: number[] = [];
  const allRemovableMines: number[] = [];

  for (let i = 0; i < b.rows * b.cols; i++) {
    const cell = b.cells[i] as Cell;
    if (!cell.isMine || forbidden.has(i)) continue;
    allRemovableMines.push(i);
    // Check if adjacent to any revealed cell
    const row = Math.floor(i / b.cols), col = i % b.cols;
    for (const n of neighbors(b.rows, b.cols, { row, col })) {
      if ((b.cells[n.row * b.cols + n.col] as Cell).state === 'revealed') {
        frontierMines.push(i);
        break;
      }
    }
  }

  const removable = frontierMines.length > 0 ? frontierMines : allRemovableMines;
  if (removable.length === 0) return b;
  const removeIdx = removable[Math.floor(rng() * removable.length)]!;

  // Non-mine cells outside forbidden zone as swap targets.
  const swapCandidates: number[] = [];
  for (let i = 0; i < b.rows * b.cols; i++) {
    if (!(b.cells[i] as Cell).isMine && !forbidden.has(i)) swapCandidates.push(i);
  }
  if (swapCandidates.length === 0) return b;
  const swapIdx = swapCandidates[Math.floor(rng() * swapCandidates.length)]!;

  const mineSet = new Set<number>();
  for (let i = 0; i < b.rows * b.cols; i++) {
    if ((b.cells[i] as Cell).isMine) mineSet.add(i);
  }
  mineSet.delete(removeIdx);
  mineSet.add(swapIdx);
  return makeBoard(b.rows, b.cols, mineSet);
}

function generateNoGuess(
  rows: number, cols: number, mineCount: number,
  firstReveal: Coord, rng: () => number, deadline: number,
): { board: Board; degraded: boolean } {
  let board = generateClassic(rows, cols, mineCount, firstReveal, rng);
  for (let attempt = 0; attempt < 600 && Date.now() < deadline; attempt++) {
    if (deductiveSolve(board, firstReveal)) return { board, degraded: false };
    board = mutateOneMine(board, firstReveal, rng);
  }
  // Timed out or exhausted attempts: return a fresh classic board.
  return { board: generateClassic(rows, cols, mineCount, firstReveal, rng), degraded: true };
}

export function generate(opts: GenerateOpts): { board: Board; degraded: boolean } {
  const { difficulty, firstReveal, mode } = opts;
  const rng = opts.rng ?? deterministicRng(Math.floor(Math.random() * 2 ** 32));
  const { rows, cols, mines: mineCount } = DIFFICULTY_PRESETS[difficulty];

  if (mode === 'classic') {
    return { board: generateClassic(rows, cols, mineCount, firstReveal, rng), degraded: false };
  }

  const timeoutMs = opts.timeoutMs ?? DEFAULT_TIMEOUTS[difficulty];
  const deadline = Date.now() + timeoutMs;
  return generateNoGuess(rows, cols, mineCount, firstReveal, rng, deadline);
}
