import { useState } from 'react';

interface ShareProps {
  date: Date;
  difficulty: string;
  timeMs: number;
  flagsUsed: number;
  hintsUsed: number;
  streak: number;
}

function pad(n: number): string {
  return String(n).padStart(2, '0');
}

function ymd(date: Date): string {
  return `${date.getUTCFullYear()}-${pad(date.getUTCMonth() + 1)}-${pad(date.getUTCDate())}`;
}

function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

export function buildShareString({ date, difficulty, timeMs, flagsUsed, hintsUsed, streak }: ShareProps): string {
  const dow = date.toLocaleString('en-US', { weekday: 'short', timeZone: 'UTC' });
  const md = `${date.getUTCMonth() + 1}/${date.getUTCDate()}`;
  const m = Math.floor(timeMs / 60_000);
  const s = Math.floor((timeMs / 1000) % 60);
  return [
    `Bilko MindSwiffer · ${dow} ${md} · ${capitalize(difficulty)}`,
    `⏱ ${m}:${pad(s)}  🚩 ${flagsUsed} flags  💡 ${hintsUsed} hints`,
    `🔥 streak ${streak}`,
    `bilko.run/projects/mindswiffer/?d=${ymd(date)}`,
  ].join('\n');
}

export function ShareTile(props: ShareProps) {
  const [copied, setCopied] = useState(false);

  const handleShare = async () => {
    const text = buildShareString(props);
    if (navigator.share) {
      try {
        await navigator.share({ text });
        return;
      } catch {
        // fall through to clipboard
      }
    }
    await navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button
      type="button"
      onClick={() => void handleShare()}
      className="ms-share-btn"
      aria-label="Share result"
    >
      {copied ? 'Copied!' : '📤 Share'}
    </button>
  );
}
