import { useEffect, useState } from 'react';
import { useHintStore } from '../features/hints/store';
import { useGameStore, useGameActions } from '../state/store';
import { nextHint } from '../engine';
import { bus } from '../lib/bus';
import { ExplanationCard, HintToast } from '../features/hints/ExplanationCard';

export function HintsSlot() {
  const board = useGameStore(s => s.board);
  const status = useGameStore(s => s.status);
  const noGuess = useGameStore(s => s.noGuess);
  const effectiveDifficulty = useGameStore(s => s.effectiveDifficulty);
  const { applyHintAction } = useGameActions();

  const level = useHintStore(s => s.level);
  const cardOpen = useHintStore(s => s.cardOpen);
  const cardText = useHintStore(s => s.cardText);
  const cardTechnique = useHintStore(s => s.cardTechnique);
  const closeCard = useHintStore(s => s.closeCard);

  const [toastVisible, setToastVisible] = useState(false);

  // Reset on new game
  useEffect(() => {
    if (status === 'idle') {
      useHintStore.setState({ level: 0, cardOpen: false });
    }
  }, [status]);

  // Auto-decay: revert level to 0 after 4s of inactivity
  useEffect(() => {
    if (level === 0) return;
    const t = setTimeout(() => {
      if (Date.now() - useHintStore.getState().lastTickAt >= 4000) {
        useHintStore.setState({ level: 0 });
      }
    }, 4100);
    return () => clearTimeout(t);
  }, [level]);

  // Process hint on level change
  useEffect(() => {
    if (level === 0) return;

    if (status !== 'playing') {
      setToastVisible(true);
      useHintStore.setState({ level: 0 });
      return;
    }

    const hint = nextHint(board, level);

    if (!hint) {
      if (noGuess) {
        // Engine contract: no-guess boards are always fully deducible — this is a bug.
        console.warn('[mindswiffer] hint_null_in_no_guess', { difficulty: effectiveDifficulty });
      }
      setToastVisible(true);
      useHintStore.setState({ level: 0 });
      return;
    }

    bus.emit('hintRequested', { level: level as 1 | 2 | 3 });

    if (level < 3) {
      useGameStore.setState({ hintHighlight: hint.cells });
      const t = setTimeout(() => useGameStore.setState({ hintHighlight: [] }), 800);
      return () => clearTimeout(t);
    }

    // level === 3: apply action + open card
    useHintStore.setState({ level: 0 }); // reset before applying to prevent re-trigger from board change
    applyHintAction(hint.action);
    useHintStore.setState({
      cardOpen: true,
      cardText: hint.explanation,
      cardTechnique: hint.technique,
    });
    const t = setTimeout(closeCard, 8000);
    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [level, board, status]);

  return (
    <>
      {cardOpen && (
        <ExplanationCard text={cardText!} technique={cardTechnique!} onClose={closeCard} />
      )}
      {toastVisible && (
        <HintToast
          message="No hint available right now"
          onDismiss={() => setToastVisible(false)}
        />
      )}
    </>
  );
}
