import { useEffect, useRef, useState } from 'react';
import './board.css';
import { Cell } from './Cell';
import { bus } from '../../lib/bus';
import { useThemeStore } from '../../features/themes/themes';
import { computeCascadeOrder } from '../../features/anim/cascade';
import type { Board as EngineBoard, Coord } from '../../engine';
import { DIFFICULTY_PRESETS } from '../../engine';

interface BoardProps {
  board: EngineBoard;
  cursor: { row: number; col: number } | null;
  hintHighlight: Coord[];
}

function boardSizeClass(rows: number, cols: number): string {
  const isSmall =
    rows <= DIFFICULTY_PRESETS.beginner.rows && cols <= DIFFICULTY_PRESETS.beginner.cols;
  return isSmall ? 'ms-board ms-board--small' : 'ms-board';
}

export function Board({ board, cursor, hintHighlight }: BoardProps) {
  const isColorblindSafe = useThemeStore((s) => s.theme === 'colorblind-safe');
  const isLost = !!board.lostAt;

  // Cascade reveal tracking
  const prevCellsRef = useRef(board.cells);
  const clickOriginRef = useRef<Coord | null>(null);
  const [cascadeSteps, setCascadeSteps] = useState<Map<string, number>>(new Map());

  // Capture click/chord origin before the board updates
  useEffect(() => {
    const offReveal = bus.on('cellRevealed', ({ row, col }) => {
      clickOriginRef.current = { row, col };
    });
    const offChord = bus.on('chordRequested', ({ row, col }) => {
      clickOriginRef.current = { row, col };
    });
    const offNew = bus.on('newGame', () => {
      setCascadeSteps(new Map());
      prevCellsRef.current = board.cells;
    });
    return () => { offReveal(); offChord(); offNew(); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // When board changes, compute cascade for newly-revealed cells
  useEffect(() => {
    const prevCells = prevCellsRef.current;
    prevCellsRef.current = board.cells;

    const origin = clickOriginRef.current;
    clickOriginRef.current = null;

    if (!origin || prevCells === board.cells) return;

    const newlyRevealed: Coord[] = [];
    for (let i = 0; i < board.cells.length; i++) {
      if (prevCells[i]?.state !== 'revealed' && board.cells[i]?.state === 'revealed') {
        newlyRevealed.push({ row: Math.floor(i / board.cols), col: i % board.cols });
      }
    }

    const reduced = matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (newlyRevealed.length > 1 && !reduced) {
      const steps = computeCascadeOrder(origin, newlyRevealed);
      setCascadeSteps(steps);
      // Clear after animation window (240ms delay + 180ms duration + buffer)
      const t = setTimeout(() => setCascadeSteps(new Map()), 500);
      return () => clearTimeout(t);
    }
  }, [board]);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (!cursor) return;
      switch (e.key) {
        case 'ArrowUp': {
          e.preventDefault();
          bus.emit('cursorMoved', { row: Math.max(0, cursor.row - 1), col: cursor.col });
          return;
        }
        case 'ArrowDown': {
          e.preventDefault();
          bus.emit('cursorMoved', { row: Math.min(board.rows - 1, cursor.row + 1), col: cursor.col });
          return;
        }
        case 'ArrowLeft': {
          e.preventDefault();
          bus.emit('cursorMoved', { row: cursor.row, col: Math.max(0, cursor.col - 1) });
          return;
        }
        case 'ArrowRight': {
          e.preventDefault();
          bus.emit('cursorMoved', { row: cursor.row, col: Math.min(board.cols - 1, cursor.col + 1) });
          return;
        }
        case ' ': {
          e.preventDefault();
          bus.emit('cellRevealed', { ...cursor, auto: false });
          return;
        }
        case 'f':
        case 'F': {
          e.preventDefault();
          bus.emit('cellFlagged', { ...cursor, flagged: true });
          return;
        }
        case 'c':
        case 'C': {
          e.preventDefault();
          bus.emit('chordRequested', cursor);
          return;
        }
        default:
          return;
      }
    };

    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [cursor, board.rows, board.cols]);

  const hintSet = new Set(hintHighlight.map(h => h.row * board.cols + h.col));

  return (
    <div
      className={boardSizeClass(board.rows, board.cols)}
      style={{ ['--rows' as string]: board.rows, ['--cols' as string]: board.cols }}
    >
      {Array.from({ length: board.rows * board.cols }, (_, i) => {
        const row = Math.floor(i / board.cols);
        const col = i % board.cols;
        const cell = board.cells[i]!;
        const key = `${row}:${col}`;
        return (
          <Cell
            key={i}
            row={row}
            col={col}
            cell={cell}
            cursor={cursor?.row === row && cursor?.col === col}
            hint={hintSet.has(i)}
            lossCell={board.lostAt?.row === row && board.lostAt?.col === col}
            isColorblindSafe={isColorblindSafe}
            isLost={isLost}
            cascadeStep={cascadeSteps.get(key)}
          />
        );
      })}
    </div>
  );
}
