import { useGameStore } from '../../state/store';
import { useStreakStore } from './streakStore';
import { dailyDifficulty } from '../../engine';
import { toYMD } from '../../lib/date';

const DIFF_INITIAL: Record<string, string> = {
  lite: 'L',
  beginner: 'B',
  intermediate: 'I',
  expert: 'E',
};

function buildCalendarDays(): Date[] {
  const today = new Date();
  today.setUTCHours(0, 0, 0, 0);
  const days: Date[] = [];
  for (let i = 89; i >= 0; i--) {
    const d = new Date(today.getTime() - i * 86_400_000);
    days.push(d);
  }
  return days;
}

/** Pad to a 7-column grid with leading empty slots so first day aligns Mon. */
function padToWeekStart(days: Date[]): (Date | null)[] {
  if (days.length === 0) return [];
  // getUTCDay: 0=Sun,1=Mon,...,6=Sat → shift so Mon=0
  const firstDow = (days[0]!.getUTCDay() + 6) % 7;
  const padding: null[] = Array(firstDow).fill(null);
  return [...padding, ...days];
}

interface Props {
  onClose(): void;
}

export function CalendarSheet({ onClose }: Props) {
  const completed = useStreakStore((s) => s.completed);
  const newGame = useGameStore((s) => s.newGame);
  const todayStr = toYMD(new Date());
  const days = buildCalendarDays();
  const padded = padToWeekStart(days);

  const handleDayClick = (date: Date) => {
    const d = toYMD(date);
    if (d > todayStr) return;
    newGame('daily', date);
    onClose();
  };

  return (
    <div
      className="ms-calendar-overlay"
      role="dialog"
      aria-modal="true"
      aria-label="Daily puzzle calendar"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
    >
      <div className="ms-calendar-sheet">
        <div className="ms-calendar-header">
          <span className="ms-calendar-title">Past puzzles</span>
          <button type="button" className="ms-calendar-close" onClick={onClose} aria-label="Close">✕</button>
        </div>

        <div className="ms-calendar-dow-labels">
          {['Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa', 'Su'].map((d) => (
            <span key={d} className="ms-calendar-dow">{d}</span>
          ))}
        </div>

        <div className="ms-calendar-grid">
          {padded.map((date, i) => {
            if (!date) {
              return <span key={`pad-${i}`} className="ms-calendar-cell ms-calendar-cell--empty" />;
            }
            const dStr = toYMD(date);
            const isFuture = dStr > todayStr;
            const isToday = dStr === todayStr;
            const isDone = completed.includes(dStr);
            const diff = dailyDifficulty(date);
            const diffInit = DIFF_INITIAL[diff] ?? '?';

            return (
              <button
                key={dStr}
                type="button"
                className="ms-calendar-cell"
                data-today={isToday || undefined}
                data-done={isDone || undefined}
                data-future={isFuture || undefined}
                disabled={isFuture}
                onClick={() => handleDayClick(date)}
                aria-label={`${dStr}${isDone ? ', completed' : ''}, ${diff}`}
              >
                <span className="ms-calendar-day">{date.getUTCDate()}</span>
                <span className="ms-calendar-meta">
                  {isDone && <span className="ms-calendar-check">✓</span>}
                  <span className="ms-calendar-diff">{diffInit}</span>
                </span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}
