let ctx: AudioContext | null = null;
const buffers = new Map<string, AudioBuffer>();
let masterGain: GainNode | null = null;
let _pendingVolume = 0.5;

export async function ensureCtx(): Promise<AudioContext> {
  if (!ctx) {
    ctx = new (window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext)();
    masterGain = ctx.createGain();
    masterGain.gain.value = _pendingVolume;
    masterGain.connect(ctx.destination);
  }
  return ctx;
}

export function setVolume(v: number): void {
  _pendingVolume = v;
  if (masterGain) masterGain.gain.value = v;
}

export async function loadBuffer(name: string, base64: string): Promise<void> {
  if (buffers.has(name)) return;
  const c = await ensureCtx();
  const binary = atob(base64);
  const arr = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) arr[i] = binary.charCodeAt(i);
  const buf = await c.decodeAudioData(arr.buffer);
  buffers.set(name, buf);
}

export async function play(name: string, gain = 1): Promise<void> {
  const c = await ensureCtx();
  if (c.state === 'suspended') await c.resume();
  const buf = buffers.get(name);
  if (!buf || !masterGain) return;
  const src = c.createBufferSource();
  src.buffer = buf;
  if (gain !== 1) {
    const g = c.createGain();
    g.gain.value = gain;
    src.connect(g);
    g.connect(masterGain);
  } else {
    src.connect(masterGain);
  }
  src.start();
}
