import { useState } from 'react';
import { useGameStore } from '../../state/store';
import { NoGuessExplainerSheet } from './NoGuessExplainerSheet';

export function NoGuessBadge() {
  const noGuess = useGameStore(state => state.noGuess);
  const degraded = useGameStore(state => state.currentGameDegraded);
  const [open, setOpen] = useState(false);

  if (!noGuess) return null;

  return (
    <>
      <button
        className="ms-no-guess-badge"
        data-degraded={degraded ? 'true' : undefined}
        onClick={() => setOpen(true)}
        aria-label={degraded ? 'Degraded — classic mines. Tap to learn more.' : 'No-guess mode active. Tap to learn more.'}
        type="button"
      >
        {degraded ? (
          <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
            <path
              d="M7 1.5L1.5 12.5h11L7 1.5z"
              stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round"
              fill="color-mix(in oklch, currentColor 15%, transparent)"
            />
            <rect x="6.5" y="5.5" width="1" height="3.5" rx="0.5" fill="currentColor"/>
            <circle cx="7" cy="10.5" r="0.6" fill="currentColor"/>
          </svg>
        ) : (
          <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
            <path
              d="M7 1.5C7 1.5 2 3 2 6.5V10l5 2.5L12 10V6.5C12 3 7 1.5 7 1.5z"
              stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round"
              fill="color-mix(in oklch, currentColor 15%, transparent)"
            />
            <path
              d="M5 7l1.5 1.5L9 5.5"
              stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"
            />
          </svg>
        )}
        <span>{degraded ? 'Degraded — classic mines' : 'No-guess'}</span>
      </button>
      {open && <NoGuessExplainerSheet onClose={() => setOpen(false)} />}
    </>
  );
}
