import { useEffect, useRef } from 'react';

const COLORS = ['var(--entered)', 'var(--mine)', 'var(--ink)', 'var(--num-3)'];

interface ConfettiProps {
  count?: number;
  durationMs?: number;
  onDone?: () => void;
}

export function Confetti({ count = 30, durationMs = 720, onDone }: ConfettiProps) {
  const reduced = useRef(matchMedia('(prefers-reduced-motion: reduce)').matches);
  const particles = useRef(
    Array.from({ length: reduced.current ? 0 : count }, (_, i) => ({
      angle: (Math.PI * 2 * i) / count + Math.random() * 0.4,
      velocity: 200 + Math.random() * 200,
      rotation: Math.random() * 360,
      color: COLORS[Math.floor(Math.random() * COLORS.length)]!,
    })),
  );
  const containerRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (reduced.current) {
      onDone?.();
      return;
    }
    const start = performance.now();
    let raf = 0;
    const tick = () => {
      const t = (performance.now() - start) / durationMs;
      if (t >= 1) {
        onDone?.();
        return;
      }
      const els = containerRef.current?.children;
      if (els) {
        for (let i = 0; i < els.length; i++) {
          const p = particles.current[i]!;
          const x = Math.cos(p.angle) * p.velocity * t;
          const y = Math.sin(p.angle) * p.velocity * t + 400 * t * t;
          (els[i] as HTMLElement).style.transform = `translate(${x}px, ${y}px) rotate(${p.rotation + 360 * t}deg)`;
          (els[i] as HTMLElement).style.opacity = `${1 - t}`;
        }
      }
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [durationMs, onDone]);

  return (
    <div
      ref={containerRef}
      className="ms-confetti"
      aria-hidden
      style={{ position: 'fixed', top: '50%', left: '50%', pointerEvents: 'none', zIndex: 1000 }}
    >
      {particles.current.map((p, i) => (
        <svg key={i} width={8} height={8} style={{ position: 'absolute', willChange: 'transform' }}>
          <rect width={8} height={8} fill={p.color} />
        </svg>
      ))}
    </div>
  );
}
