import { Board, Cell, Coord, neighbors } from './board';
import { isWon, isLost } from './actions';

export type HintTechnique =
  | 'single-cell-flag'
  | 'single-cell-reveal'
  | 'subset-deduction'
  | 'constraint-propagation';

export interface Hint {
  technique: HintTechnique;
  /** Source cells whose constraint we used. */
  cells: Coord[];
  action: { type: 'reveal' | 'flag'; cells: Coord[] };
  explanation: string;
  level: 1 | 2 | 3;
}

interface Constraint {
  source: Coord;
  mines: number;
  cells: number[];
}

function buildConstraints(b: Board): Constraint[] {
  const result: Constraint[] = [];
  for (let r = 0; r < b.rows; r++) {
    for (let c = 0; c < b.cols; c++) {
      const cell = b.cells[r * b.cols + c] as Cell;
      if (cell.state !== 'revealed' || cell.count <= 0) continue;
      const ns = neighbors(b.rows, b.cols, { row: r, col: c });
      const covered: number[] = [];
      let flaggedCount = 0;
      for (const n of ns) {
        const nc = b.cells[n.row * b.cols + n.col] as Cell;
        if (nc.state === 'covered') covered.push(n.row * b.cols + n.col);
        else if (nc.state === 'flagged') flaggedCount++;
      }
      const remaining = cell.count - flaggedCount;
      if (covered.length > 0 && remaining >= 0) {
        result.push({ source: { row: r, col: c }, mines: remaining, cells: covered });
      }
    }
  }
  return result;
}

function idxToCoord(idx: number, cols: number): Coord {
  return { row: Math.floor(idx / cols), col: idx % cols };
}

function buildHint(
  level: 1 | 2 | 3,
  technique: HintTechnique,
  sourceCells: Coord[],
  actionType: 'reveal' | 'flag',
  actionCells: Coord[],
  explanation: string,
): Hint {
  if (level === 1) {
    return { technique, cells: sourceCells, action: { type: actionType, cells: [] }, explanation: '', level };
  }
  if (level === 2) {
    return { technique, cells: [...sourceCells, ...actionCells], action: { type: actionType, cells: [] }, explanation: '', level };
  }
  return { technique, cells: [...sourceCells, ...actionCells], action: { type: actionType, cells: actionCells }, explanation, level };
}

function trySingleCell(b: Board, constraints: Constraint[], level: 1 | 2 | 3): Hint | null {
  for (const c of constraints) {
    if (c.cells.length === 0) continue;
    if (c.mines === c.cells.length) {
      const targets = c.cells.map(i => idxToCoord(i, b.cols));
      return buildHint(
        level, 'single-cell-flag', [c.source], 'flag', targets,
        `Cell at (${c.source.row},${c.source.col}) shows ${c.mines}; all ${c.cells.length} remaining neighbor${c.cells.length > 1 ? 's are' : ' is'} mine${c.cells.length > 1 ? 's' : ''}. Flag them.`,
      );
    }
    if (c.mines === 0) {
      const targets = c.cells.map(i => idxToCoord(i, b.cols));
      return buildHint(
        level, 'single-cell-reveal', [c.source], 'reveal', targets,
        `Cell at (${c.source.row},${c.source.col}) shows ${(b.cells[c.source.row * b.cols + c.source.col] as Cell).count}; all mine neighbors are flagged. Reveal the rest.`,
      );
    }
  }
  return null;
}

function trySubset(b: Board, constraints: Constraint[], level: 1 | 2 | 3): Hint | null {
  for (let i = 0; i < constraints.length; i++) {
    const a = constraints[i]!;
    const setA = new Set(a.cells);
    for (let j = 0; j < constraints.length; j++) {
      if (i === j) continue;
      const bC = constraints[j]!;
      if (a.cells.length >= bC.cells.length) continue;
      if (!a.cells.every(ci => bC.cells.includes(ci))) continue;
      const diff = bC.cells.filter(ci => !setA.has(ci));
      const diffMines = bC.mines - a.mines;
      if (diffMines < 0 || diffMines > diff.length || diff.length === 0) continue;
      const targets = diff.map(idx => idxToCoord(idx, b.cols));
      if (diffMines === diff.length) {
        return buildHint(
          level, 'subset-deduction', [a.source, bC.source], 'flag', targets,
          `Constraint at (${a.source.row},${a.source.col}) is a subset of (${bC.source.row},${bC.source.col}). The ${diff.length} remaining cell${diff.length > 1 ? 's' : ''} must be mine${diff.length > 1 ? 's' : ''}.`,
        );
      }
      if (diffMines === 0) {
        return buildHint(
          level, 'subset-deduction', [a.source, bC.source], 'reveal', targets,
          `Constraint at (${a.source.row},${a.source.col}) is a subset of (${bC.source.row},${bC.source.col}) with equal mine counts. The ${diff.length} remaining cell${diff.length > 1 ? 's' : ''} must be safe.`,
        );
      }
    }
  }
  return null;
}

function tryCsp(b: Board, constraints: Constraint[], level: 1 | 2 | 3): Hint | null {
  if (constraints.length === 0) return null;

  const parent = new Map<number, number>();
  const find = (x: number): number => {
    if (!parent.has(x)) parent.set(x, x);
    const p = parent.get(x)!;
    if (p !== x) { const r = find(p); parent.set(x, r); return r; }
    return x;
  };
  const union = (x: number, y: number) => parent.set(find(x), find(y));
  for (const c of constraints) for (let i = 1; i < c.cells.length; i++) union(c.cells[0]!, c.cells[i]!);

  const clusterCells = new Map<number, number[]>();
  const clusterConstraints = new Map<number, Constraint[]>();
  const allFrontier = new Set<number>();
  for (const c of constraints) for (const idx of c.cells) allFrontier.add(idx);
  for (const idx of allFrontier) {
    const root = find(idx);
    if (!clusterCells.has(root)) clusterCells.set(root, []);
    clusterCells.get(root)!.push(idx);
  }
  for (const c of constraints) {
    if (c.cells.length === 0) continue;
    const root = find(c.cells[0]!);
    if (!clusterConstraints.has(root)) clusterConstraints.set(root, []);
    clusterConstraints.get(root)!.push(c);
  }

  for (const [root, cells] of clusterCells) {
    if (cells.length > 20) continue;
    const clustConst = clusterConstraints.get(root) ?? [];
    const indexMap = new Map(cells.map((idx, i) => [idx, i]));
    const mineVotes = new Array<number>(cells.length).fill(0);
    let validCount = 0;
    const assignment = new Array<number>(cells.length).fill(-1);

    const check = (): boolean => {
      for (const c of clustConst) {
        let mines = 0, unknowns = 0;
        for (const idx of c.cells) {
          const i = indexMap.get(idx); if (i === undefined) continue;
          const v = assignment[i]!;
          if (v === 1) mines++; else if (v === -1) unknowns++;
        }
        if (mines > c.mines || mines + unknowns < c.mines) return false;
      }
      return true;
    };
    const backtrack = (depth: number): void => {
      if (!check()) return;
      if (depth === cells.length) { validCount++; for (let i = 0; i < cells.length; i++) if (assignment[i]! === 1) mineVotes[i]!++; return; }
      for (const v of [0, 1]) { assignment[depth] = v; backtrack(depth + 1); }
      assignment[depth] = -1;
    };
    backtrack(0);
    if (validCount === 0) continue;

    for (let i = 0; i < cells.length; i++) {
      const idx = cells[i]!;
      if ((b.cells[idx] as Cell).state !== 'covered') continue;
      const coord = idxToCoord(idx, b.cols);
      // Find which constraints touch this cell for attribution.
      const sources = clustConst.filter(c => c.cells.includes(idx)).map(c => c.source);
      if (mineVotes[i] === 0) {
        return buildHint(level, 'constraint-propagation', sources, 'reveal', [coord],
          `Constraint propagation over ${cells.length} cells shows (${coord.row},${coord.col}) is safe in all valid mine assignments.`);
      }
      if (mineVotes[i] === validCount) {
        return buildHint(level, 'constraint-propagation', sources, 'flag', [coord],
          `Constraint propagation over ${cells.length} cells shows (${coord.row},${coord.col}) is a mine in all valid mine assignments.`);
      }
    }
  }
  return null;
}

export function nextHint(b: Board, level: 1 | 2 | 3): Hint | null {
  if (isWon(b) || isLost(b)) return null;
  const constraints = buildConstraints(b);
  return trySingleCell(b, constraints, level)
    ?? trySubset(b, constraints, level)
    ?? tryCsp(b, constraints, level);
}
