import { bus } from '../../lib/bus';
import { play, setVolume } from './audio';
import { vibrate } from './haptics';
import { useSettingsStore } from '../../state/settings';

export function startSoundHapticsSubscriber(): void {
  const get = () => useSettingsStore.getState();

  bus.on('cellRevealed', ({ auto }) => {
    if (auto) return;
    if (get().sounds) void play('reveal');
    if (get().haptics) vibrate(5);
  });

  bus.on('cellFlagged', ({ flagged }) => {
    if (get().sounds) void play('place-flag', flagged ? 1 : 0.6);
    if (get().haptics) vibrate(15);
  });

  bus.on('chordRequested', () => {
    if (get().sounds) void play('chord');
    if (get().haptics) vibrate([5, 30, 5]);
  });

  bus.on('gameWon', () => {
    if (get().sounds) void play('win');
    if (get().haptics) vibrate([20, 30, 20]);
  });

  bus.on('gameLost', () => {
    if (get().sounds) void play('lose');
    if (get().haptics) vibrate([40]);
  });

  bus.on('hintRequested', ({ level }) => {
    if (level === 3 && get().sounds) void play('hint');
  });

  setVolume(get().soundVolume / 100);
  useSettingsStore.subscribe(s => setVolume(s.soundVolume / 100));
}
