/**
 * Deductive solver used internally by the no-guess generator.
 * Simulates a player who never guesses: only reveals cells provably safe
 * and flags cells provably mines. Returns true if the board is fully solved.
 */
import { Board, Cell, Coord, neighbors } from './board';
import { reveal, flag, isWon } from './actions';

interface Constraint {
  /** Remaining mine count after accounting for flagged neighbors. */
  mines: number;
  /** Flat indices of covered (not-flagged) neighbors. */
  cells: number[];
}

function buildConstraints(b: Board): Constraint[] {
  const constraints: Constraint[] = [];
  for (let r = 0; r < b.rows; r++) {
    for (let c = 0; c < b.cols; c++) {
      const cell = b.cells[r * b.cols + c] as Cell;
      if (cell.state !== 'revealed' || cell.count <= 0) continue;
      const ns = neighbors(b.rows, b.cols, { row: r, col: c });
      const covered: number[] = [];
      let flaggedCount = 0;
      for (const n of ns) {
        const nc = b.cells[n.row * b.cols + n.col] as Cell;
        if (nc.state === 'covered') covered.push(n.row * b.cols + n.col);
        else if (nc.state === 'flagged') flaggedCount++;
      }
      const remaining = cell.count - flaggedCount;
      if (covered.length > 0 && remaining >= 0) {
        constraints.push({ mines: remaining, cells: covered });
      }
    }
  }
  return constraints;
}

function applySingleCell(b: Board, constraints: Constraint[]): { board: Board; progress: boolean } {
  let progress = false;
  for (const c of constraints) {
    if (c.cells.length === 0 || c.mines < 0) continue;
    if (c.mines === c.cells.length) {
      for (const idx of c.cells) {
        const coord: Coord = { row: Math.floor(idx / b.cols), col: idx % b.cols };
        if ((b.cells[idx] as Cell).state === 'covered') { b = flag(b, coord); progress = true; }
      }
    } else if (c.mines === 0) {
      for (const idx of c.cells) {
        const coord: Coord = { row: Math.floor(idx / b.cols), col: idx % b.cols };
        if ((b.cells[idx] as Cell).state === 'covered') {
          b = reveal(b, coord);
          if (b.lostAt) return { board: b, progress };
          progress = true;
        }
      }
    }
  }
  return { board: b, progress };
}

function applySubset(b: Board, constraints: Constraint[]): { board: Board; progress: boolean } {
  let progress = false;
  for (let i = 0; i < constraints.length; i++) {
    const a = constraints[i]!;
    const setA = new Set(a.cells);
    for (let j = 0; j < constraints.length; j++) {
      if (i === j) continue;
      const bC = constraints[j]!;
      if (a.cells.length >= bC.cells.length) continue;
      if (!a.cells.every(ci => bC.cells.includes(ci))) continue;
      const diff = bC.cells.filter(ci => !setA.has(ci));
      const diffMines = bC.mines - a.mines;
      if (diffMines < 0 || diffMines > diff.length || diff.length === 0) continue;
      if (diffMines === diff.length) {
        for (const idx of diff) {
          const coord: Coord = { row: Math.floor(idx / b.cols), col: idx % b.cols };
          if ((b.cells[idx] as Cell).state === 'covered') { b = flag(b, coord); progress = true; }
        }
      } else if (diffMines === 0) {
        for (const idx of diff) {
          const coord: Coord = { row: Math.floor(idx / b.cols), col: idx % b.cols };
          if ((b.cells[idx] as Cell).state === 'covered') {
            b = reveal(b, coord);
            if (b.lostAt) return { board: b, progress };
            progress = true;
          }
        }
      }
    }
  }
  return { board: b, progress };
}

function applyGlobal(b: Board): { board: Board; progress: boolean } {
  const covered: Coord[] = [];
  let flaggedCount = 0;
  for (let r = 0; r < b.rows; r++) {
    for (let c = 0; c < b.cols; c++) {
      const cell = b.cells[r * b.cols + c] as Cell;
      if (cell.state === 'covered') covered.push({ row: r, col: c });
      else if (cell.state === 'flagged') flaggedCount++;
    }
  }
  const remaining = b.mineCount - flaggedCount;
  if (covered.length === 0) return { board: b, progress: false };
  let progress = false;
  if (remaining === covered.length) {
    for (const c of covered) { b = flag(b, c); progress = true; }
  } else if (remaining === 0) {
    for (const c of covered) {
      b = reveal(b, c);
      if (b.lostAt) return { board: b, progress };
      progress = true;
    }
  }
  return { board: b, progress };
}

function applyCsp(b: Board, constraints: Constraint[]): { board: Board; progress: boolean } {
  if (constraints.length === 0) return { board: b, progress: false };

  // Union-find to cluster frontier cells that share constraints.
  const parent = new Map<number, number>();
  const find = (x: number): number => {
    if (!parent.has(x)) parent.set(x, x);
    const p = parent.get(x)!;
    if (p !== x) { const r = find(p); parent.set(x, r); return r; }
    return x;
  };
  const union = (x: number, y: number) => parent.set(find(x), find(y));

  for (const c of constraints) {
    for (let i = 1; i < c.cells.length; i++) union(c.cells[0]!, c.cells[i]!);
  }

  const clusterCells = new Map<number, number[]>();
  const clusterConstraints = new Map<number, Constraint[]>();
  const allFrontier = new Set<number>();
  for (const c of constraints) for (const idx of c.cells) allFrontier.add(idx);

  for (const idx of allFrontier) {
    const root = find(idx);
    if (!clusterCells.has(root)) clusterCells.set(root, []);
    clusterCells.get(root)!.push(idx);
  }
  for (const c of constraints) {
    if (c.cells.length === 0) continue;
    const root = find(c.cells[0]!);
    if (!clusterConstraints.has(root)) clusterConstraints.set(root, []);
    clusterConstraints.get(root)!.push(c);
  }

  let progress = false;

  for (const [root, cells] of clusterCells) {
    if (cells.length > 20) continue; // Skip large clusters; too expensive.

    const clustConst = clusterConstraints.get(root) ?? [];
    const indexMap = new Map(cells.map((idx, i) => [idx, i]));
    const mineVotes = new Array<number>(cells.length).fill(0);
    let validCount = 0;
    const assignment = new Array<number>(cells.length).fill(-1);

    // Checks whether the current partial assignment is consistent with all constraints.
    // At depth == cells.length all variables are assigned; remaining > 0 means unsatisfied.
    const check = (): boolean => {
      for (const c of clustConst) {
        let mines = 0, unknowns = 0;
        for (const idx of c.cells) {
          const i = indexMap.get(idx);
          if (i === undefined) continue;
          const v = assignment[i]!;
          if (v === 1) mines++;
          else if (v === -1) unknowns++;
        }
        if (mines > c.mines) return false;
        if (mines + unknowns < c.mines) return false;
      }
      return true;
    };

    const backtrack = (depth: number): void => {
      if (!check()) return;
      if (depth === cells.length) {
        validCount++;
        for (let i = 0; i < cells.length; i++) {
          if (assignment[i]! === 1) mineVotes[i]!++;
        }
        return;
      }
      for (const v of [0, 1]) {
        assignment[depth] = v;
        backtrack(depth + 1);
      }
      assignment[depth] = -1;
    };

    backtrack(0);
    if (validCount === 0) continue;

    for (let i = 0; i < cells.length; i++) {
      const idx = cells[i]!;
      const cell = b.cells[idx] as Cell;
      if (cell.state !== 'covered') continue;
      const coord: Coord = { row: Math.floor(idx / b.cols), col: idx % b.cols };
      if (mineVotes[i] === 0) {
        b = reveal(b, coord);
        if (b.lostAt) return { board: b, progress };
        progress = true;
      } else if (mineVotes[i] === validCount) {
        b = flag(b, coord);
        progress = true;
      }
    }
  }

  return { board: b, progress };
}

/**
 * Attempts to solve `board` from `firstReveal` using only deduction.
 * Returns true if the board is fully solved without guessing.
 */
export function deductiveSolve(board: Board, firstReveal: Coord): boolean {
  let b = reveal(board, firstReveal);
  if (b.lostAt) return false; // firstReveal is a mine — generator bug

  let progress = true;
  while (progress) {
    progress = false;
    if (isWon(b)) return true;

    let res = applyGlobal(b);
    b = res.board; if (b.lostAt) return false; if (res.progress) { progress = true; continue; }

    const constraints = buildConstraints(b);

    res = applySingleCell(b, constraints);
    b = res.board; if (b.lostAt) return false; if (res.progress) { progress = true; continue; }

    res = applySubset(b, constraints);
    b = res.board; if (b.lostAt) return false; if (res.progress) { progress = true; continue; }

    res = applyCsp(b, constraints);
    b = res.board; if (b.lostAt) return false; if (res.progress) { progress = true; continue; }
  }

  return isWon(b);
}
