import type { Coord } from '../../engine';

// O(n) over revealed cells. Capped at 6 steps (6 × 40ms = 240ms ≤ 250ms cap).
export function computeCascadeOrder(clicked: Coord, revealed: Coord[]): Map<string, number> {
  const byDist = new Map<number, Coord[]>();
  for (const c of revealed) {
    const d = Math.abs(c.row - clicked.row) + Math.abs(c.col - clicked.col);
    if (!byDist.has(d)) byDist.set(d, []);
    byDist.get(d)!.push(c);
  }
  const dists = [...byDist.keys()].sort((a, b) => a - b);
  const out = new Map<string, number>();
  dists.forEach((d, i) => {
    const step = Math.min(i, 6);
    for (const c of byDist.get(d)!) out.set(`${c.row}:${c.col}`, step);
  });
  return out;
}
